const e={categories:[{id:"cause-of-death",name:"💀 CAUSE OF DEATH",emoji:"💀",lists:[{id:"cause_no_market",name:"THE HALLUCINATIONS",icon:"🔮",slug:"cause_no_market",vibe:"They built solutions for problems that didn't exist."},{id:"cause_cash_burn",name:"THE BONFIRES",icon:"🔥",slug:"cause_cash_burn",vibe:"We lose money on every sale, but make it up in volume."},{id:"cause_legal",name:"THE OUTLAWS",icon:"⚖️",slug:"cause_legal",vibe:"They fought the law"},{id:"cause_competition",name:"THE CRUSHED",icon:"🐜",slug:"cause_competition",vibe:"Good products that got eaten by Google/Facebook/Amazon."},{id:"cause_product",name:"THE LEMONS",icon:"🍋",slug:"cause_product",vibe:"The tech was vaporware."},{id:"cause_unit_econ",name:"THE MATH PROBLEMS",icon:"➗",slug:"cause_unit_econ",vibe:"CAC > LTV. The economics never made sense."}]},{id:"sectors",name:"🏭 SECTORS",emoji:"🏭",lists:[{id:"sec_fintech",name:"FINTECH FLOPS",icon:"💸",slug:"sec_fintech",vibe:"Neo-banks and lending protocols that imploded."},{id:"sec_crypto",name:"CRYPTO RUGS",icon:"📉",slug:"sec_crypto",vibe:"Billions in value"},{id:"sec_edtech",name:"EDTECH DROPOUTS",icon:"🎓",slug:"sec_edtech",vibe:"The post-COVID crash victims."},{id:"sec_health",name:"BIOHAZARDS",icon:"☣️",slug:"sec_health",vibe:"Biotech bets and digital health apps that flatlined."},{id:"sec_hardware",name:"HARDWARE BRICKS",icon:"🧱",slug:"sec_hardware",vibe:"IoT"},{id:"sec_saas_b2b",name:"SAAS GRAVES (B2B)",icon:"👔",slug:"sec_saas_b2b",vibe:"Enterprise tools that nobody wanted to pay for."},{id:"sec_saas_b2c",name:"CHURN CITY (B2C)",icon:"📉",slug:"sec_saas_b2c",vibe:"Consumer apps that couldn't retain users."},{id:"sec_social",name:"SOCIAL GHOST TOWNS",icon:"👻",slug:"sec_social",vibe:"Apps that tried to kill Twitter and Instagram."},{id:"sec_proptech",name:"PROPTECH CRASHES",icon:"🏘️",slug:"sec_proptech",vibe:"The WeWork wannabes."},{id:"sec_clean",name:"GREEN WASHED",icon:"♻️",slug:"sec_clean",vibe:"Energy projects that ran out of juice."},{id:"sec_market",name:"EMPTY MARKETPLACES",icon:"🛒",slug:"sec_market",vibe:"Supply was there"},{id:"sec_ai",name:"ARTIFICIAL STUPIDITY",icon:"🤖",slug:"sec_ai",vibe:"The first wave of AI startups that hallucinated their revenue."},{id:"sec_devtools",name:"DEAD CODE",icon:"💻",slug:"sec_devtools",vibe:"Dev tools that engineers refused to use."}]},{id:"timeline",name:"📅 TIMELINE",emoji:"📅",lists:[{id:"time_zirp",name:"THE ZIRP VICTIMS",icon:"📉",slug:"time_zirp",vibe:"Companies that only lived because interest rates were 0%."},{id:"time_covid",name:"COVID BUBBLE POPS",icon:"😷",slug:"time_covid",vibe:"Hopin clones and 15-minute delivery services."},{id:"time_dotcom",name:"DOT COM DINOSAURS",icon:"🦖",slug:"time_dotcom",vibe:"The original internet bubble."}]},{id:"atlas",name:"🌍 ATLAS",emoji:"🌍",lists:[{id:"geo_usa",name:"SV BURN PILES",icon:"🇺🇸",slug:"geo_usa",vibe:"The most expensive failures in the world."},{id:"geo_asia",name:"THE TIGER CUBS",icon:"🐯",slug:"geo_asia",vibe:"High growth startups funded by aggressive global capital."},{id:"geo_eu",name:"EURO-TRASHED",icon:"🇪🇺",slug:"geo_eu",vibe:"GDPR victims and localized clones that failed to scale."}]},{id:"special",name:"🔬 SPECIAL",emoji:"🔬",lists:[{id:"spec_speed",name:"SPEED RUNS",icon:"⚡",slug:"spec_speed",vibe:"How to lose $50M+ in under 24 months."},{id:"spec_zombie",name:"ZOMBIES",icon:"🧟",slug:"spec_zombie",vibe:"The walking dead: Long life"},{id:"spec_bootstrap",name:"DAVIDS THAT DIED",icon:"⛺",slug:"spec_bootstrap",vibe:"Great ideas that just ran out of gas (Bootstrapped)."}]}],lists:{cause_no_market:{title:"TOP 10: THE HALLUCINATIONS",subtitle:"They built solutions for problems that didn't exist.",slug:"cause_no_market",icon:"🔮",items:[{rank:1,name:"Quibi",country:"USA 🇺🇸",lootLost:"$1.8B",livedYears:"~6 Months (Active)",causeTag:"NO MARKET NEED",valueProp:"Netflix for your pocket—billions spent on 10-minute Hollywood episodes designed for subways and coffee breaks.",causeOfDeath:"They bet $1.75B on commuting right before the world entered lockdown, and refused to let users cast to TV until it was too late.",tldr:"They built a subway app for a world that started working from bed."},{rank:2,name:"Hopin",country:"UK/USA 🇬🇧",lootLost:"$1.1B",livedYears:"~5 Years",causeTag:"NO MARKET NEED",valueProp:"The first Virtual Venue that actually felt like a conference (networking roulette, stages, expo halls) during the peak of COVID.",causeOfDeath:"A feature posing as a company; when the world reopened, nobody wanted to hang out in a browser tab anymore, and the $7.7B valuation vaporized.",tldr:"The fastest unicorn in history became a zombie the moment the masks came off."},{rank:3,name:"Udacity",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~13 Years",causeTag:"NO MARKET NEED",valueProp:"The original MOOC that promised to replace Universities with Nanodegrees co-created by Google and Facebook.",causeOfDeath:"Education requires services, not just content; they couldn't make the unit economics of human grading work at venture scale.",tldr:"They tried to automate the professor but ended up just building a video library."},{rank:4,name:"Better Place",country:"Israel 🇮🇱",lootLost:"$850M",livedYears:"~6 Years",causeTag:"NO MARKET NEED",valueProp:"Gas stations for electricity—a network of automated battery-swapping robots so you never had to wait for a charge.",causeOfDeath:"The God Complex—they demanded auto manufacturers redesign their car chassis to fit Better Place's batteries. Only Renault listened.",tldr:"They tried to be the Apple of cars without building the car."},{rank:5,name:"Coinbase NFT",country:"USA 🇺🇸",lootLost:"$800M",livedYears:"~1 Year",causeTag:"NO MARKET NEED",valueProp:"A Social Marketplace for NFTs where you could comment on JPEGs, intended to kill OpenSea.",causeOfDeath:"They launched a community tool two weeks after the NFT bubble popped, resulting in fewer than 100 transactions in their first week.",tldr:"They threw a launch party in an empty stadium after the game had already ended."},{rank:6,name:"Essential Products",country:"USA 🇺🇸",lootLost:"$330M",livedYears:"~5 Years",causeTag:"NO MARKET NEED",valueProp:"The Anti-iPhone built by Android's creator, promising titanium materials and modular magnetic accessories.",causeOfDeath:"A toxic mix of founder scandals and the realization that consumers care more about camera quality than titanium edges.",tldr:"A billion-dollar valuation for a phone that took worse photos than a mid-tier Samsung."},{rank:7,name:"Quora Credits",country:"USA 🇺🇸",lootLost:"$85M",livedYears:"~1 Year",causeTag:"NO MARKET NEED",valueProp:"A virtual currency system intended to pay experts for answers and let users bounty difficult questions.",causeOfDeath:"They transactionalized social capital; users stopped writing for passion because they were waiting to be paid in fake internet points.",tldr:"They tried to turn a dinner party conversation into a flea market transaction."},{rank:8,name:"Neeva",country:"USA 🇺🇸",lootLost:"$77M",livedYears:"~4 Years",causeTag:"NO MARKET NEED",valueProp:"The Privacy First search engine—no ads, no tracking, just a monthly subscription for pure search results.",causeOfDeath:"The Google Problem—99.9% of humans will tolerate surveillance if the product is free, and the other 0.1% aren't enough to sustain a business.",tldr:"You can't sell ice to eskimos, and you can't sell search to people addicted to free."},{rank:9,name:"Koo",country:"India 🇮🇳",lootLost:"$60M",livedYears:"~4 Years",causeTag:"NO MARKET NEED",valueProp:"The Twitter for India—a vernacular micro-blogging platform built to capitalize on the Indian government's feud with Twitter.",causeOfDeath:"Purely political product-market fit; once the government feuds cooled down, the reason for its existence vanished.",tldr:"If your only feature is We aren't Twitter, you die when Twitter changes."},{rank:10,name:"Doppler Labs",country:"USA 🇺🇸",lootLost:"$51M",livedYears:"~4 Years",causeTag:"NO MARKET NEED",valueProp:"Bionic Hearing—smart earbuds (Here One) that let you EQ the real world, turning down a crying baby or boosting a concert.",causeOfDeath:"They tried to beat Apple to the punch; they shipped a buggy product with 2-hour battery life just months before AirPods Pro did it perfectly.",tldr:"They brought a prototype to a knife fight against Apple."}]},cause_cash_burn:{title:"TOP 10: THE BONFIRES",subtitle:"We lose money on every sale, but make it up in volume.",slug:"cause_cash_burn",icon:"🔥",items:[{rank:1,name:"Silicon Valley Bank",country:"USA 🇺🇸",lootLost:"$209B",livedYears:"~40 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Central Bank of Startups—the only bank that understood founders, offering venture debt and networking when others said no.",causeOfDeath:"The Duration Mismatch. They bought long-term bonds with short-term deposits. When rates rose and tech funding dried up, clients panicked.",tldr:"They died because their customers (VCs) have a WhatsApp group and zero loyalty."},{rank:2,name:"Wirecard",country:"Germany 🇩🇪",lootLost:"$28B",livedYears:"~21 Years",causeTag:"RAN OUT OF CASH",valueProp:"The PayPal of Europe—a payment processor that claimed to handle billions in transactions for casinos and porn sites seamlessly.",causeOfDeath:"The Fake Cash. They claimed €1.9B was sitting in a Philippine bank account. It wasn't. The entire business was a spreadsheet of lies.",tldr:"The Enron of Fintech: They made up the money, then sued the journalists who noticed."},{rank:3,name:"WeWork",country:"USA 🇺🇸",lootLost:"$22B",livedYears:"~13 Years",causeTag:"RAN OUT OF CASH",valueProp:"Space as a Service—office subleasing with beer taps and neon signs, promising to elevate the consciousness of the world.",causeOfDeath:"The Liability Trap. They signed 15-year leases (debt) but sold monthly memberships (revenue). When the hype died, the rent was still due.",tldr:"The most expensive rental agreement in history."},{rank:4,name:"Northvolt",country:"Sweden 🇸🇪",lootLost:"$15B",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Green Hope of Europe—a gigafactory to break China's battery monopoly, backed by VW and BMW.",causeOfDeath:"Production Hell. They raised $15B but couldn't figure out how to manufacture batteries at scale without a 50% defect rate.",tldr:"You can't copy-paste a Gigafactory just because you have the blueprints."},{rank:5,name:"Ezubao",country:"China 🇨🇳",lootLost:"$7.6B",livedYears:"~2 Years",causeTag:"RAN OUT OF CASH",valueProp:"A P2P lending platform offering guaranteed 15% returns to retail investors, supposedly backing infrastructure projects.",causeOfDeath:"The Ponzi. 95% of the investment projects were fake. They used new investor money to pay for the founder's lavish lifestyle and gifts.",tldr:"A $7.6B robbery disguised as a finance app."},{rank:6,name:"Byju's",country:"India 🇮🇳",lootLost:"$6B",livedYears:"~13 Years",causeTag:"RAN OUT OF CASH",valueProp:"The World's Most Valuable EdTech—gamified learning apps for kids sold via high-pressure sales tactics to anxious parents.",causeOfDeath:"The Acquisition Binge. They spent billions buying companies (WhiteHat Jr) to hide slowing growth. When the auditors checked the books, the cash was gone.",tldr:"They sold fear to parents and bought growth with debt."},{rank:7,name:"LeEco",country:"China 🇨🇳",lootLost:"$6B",livedYears:"~13 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Everything Store—Netflix, Tesla, Apple, and TV manufacturer all rolled into one massive ecosystem.",causeOfDeath:"The Leverage suicide. The founder pledged his own stock to borrow billions to expand into the US. When cash flow slowed, the house of cards collapsed.",tldr:"They tried to fight Apple, Netflix, and Tesla at the same time and lost to all of them."},{rank:8,name:"WM Motor",country:"China 🇨🇳",lootLost:"$5.8B",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"EVs for the Masses—affordable electric SUVs for the middle class, backed by Baidu and Tencent.",causeOfDeath:"The Squeeze. They didn't have the luxury margins of Nio or the scale of BYD. They died in the middle market valley of death.",tldr:"Being average in a price war is a death sentence."},{rank:9,name:"Panda Auto",country:"China 🇨🇳",lootLost:"$4.6B",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"A car-sharing platform (like Zipcar) using EVs, backed by the major auto manufacturer Lifan.",causeOfDeath:"The Asset Heavy Trap. They owned the cars. Cars depreciate. Maintenance costs exploded. The parent company (Lifan) went bankrupt, dragging them down.",tldr:"Owning 20,000 depreciating assets isn't a tech company, it's a junkyard."},{rank:10,name:"Pluralsight",country:"USA 🇺🇸",lootLost:"$4B",livedYears:"~20 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Dev Skilling Platform—video courses to help engineers learn new frameworks, sold to enterprises.",causeOfDeath:"The Debt Zombie. Acquired by PE (Vista) for billions in debt. When AI (ChatGPT) made coding tutorials free, their revenue couldn't cover the interest payments.",tldr:"Lenders took the keys because learning to code became free overnight."}]},cause_conflict:{title:"TOP 10: THE CIVIL WARS",subtitle:"When the biggest threat to the company is the co-founder.",slug:"cause_conflict",icon:"⚔️",items:[{rank:1,name:"TuSimple",country:"USA/China 🇺🇸🇨🇳",lootLost:"$1B",livedYears:"~9 Years",causeTag:"CONFLICT",valueProp:"Autonomous Trucking—self-driving semi-trucks that promised to automate freight between the US and China.",causeOfDeath:"The Geopolitical Divorce. The US government suspected them of sharing tech with China. The Board fired the CEO; the Founders then fired the Board. Total chaos.",tldr:"You can't automate trucks if the FBI is investigating your source code."},{rank:2,name:"Mozido",country:"USA 🇺🇸",lootLost:"$250M",livedYears:"~13 Years",causeTag:"CONFLICT",valueProp:"The Mobile Wallet for the Unbanked—promised to bring financial services to billions of people in developing nations using basic cell phones.",causeOfDeath:"The Theranos of Payments. The founder (Michael Liberty) used the company as a personal piggy bank to pay for private jets and shell companies. It was a Ponzi scheme.",tldr:"They raised $300M to bank the unbanked, but only banked the founder."},{rank:3,name:"ArsDigita",country:"USA 🇺🇸",lootLost:"$38M",livedYears:"~8 Years",causeTag:"CONFLICT",valueProp:"The original Shopify—built high-end e-commerce sites for Fortune 500s using open-source tools (AOLServer/Oracle) in the late 90s.",causeOfDeath:"The VC Coup. The founder (Philip Greenspun) refused to play corporate. VCs (Greylock) sued him, seized the company, spent $20M to rewrite the code in Java, and drove revenue to zero.",tldr:"The VCs spent $20M to fix code that wasn't broken, just to spite the founder."},{rank:4,name:"Secret",country:"USA 🇺🇸",lootLost:"$35M",livedYears:"~1.5 Years",causeTag:"CONFLICT",valueProp:"An anonymous social network where you could share gossip with friends without revealing your identity.",causeOfDeath:"The Conscience Crisis. It became a toxic hive of cyberbullying. The founder (David Byttow) felt so guilty about what he created that he shut it down despite having $35M in the bank.",tldr:"The founder looked in the mirror, hated what he saw, and pulled the plug."},{rank:5,name:"Skully",country:"USA 🇺🇸",lootLost:"$15M",livedYears:"~3 Years",causeTag:"CONFLICT",valueProp:"The Iron Man Helmet—a motorcycle helmet with a built-in HUD (Heads Up Display) and rear-view camera.",causeOfDeath:"The Looting. The founders allegedly spent the Indiegogo money on strip clubs, a Lamborghini, and a trip to Hawaii instead of manufacturing the helmets.",tldr:"They spent the R&D budget on lap dances and fast cars."},{rank:6,name:"Lieferoo",country:"Germany 🇩🇪",lootLost:"$8M",livedYears:"~1 Year",causeTag:"CONFLICT",valueProp:"Uber for Awkward Items—a crowd-shipping platform to move furniture and heavy goods across cities.",causeOfDeath:"The Abandonment. The technical co-founder lost interest and moved back to Nepal. The CEO hired a replacement who just wanted to do documentation. The passion evaporated.",tldr:"If your CTO moves to the Himalayas, your code isn't getting shipped."},{rank:7,name:"Flux",country:"USA 🇺🇸",lootLost:"$7M",livedYears:"~6 Years",causeTag:"CONFLICT",valueProp:"A Google X spinout trying to use AI to solve construction—sharing architectural data seamlessly between disparate software tools.",causeOfDeath:"The Culture Clash. They hired brilliant Google software engineers who didn't respect the messy, low-tech reality of the construction industry. The product was perfect but unusable.",tldr:"Silicon Valley arrogance met the concrete wall of the construction industry."},{rank:8,name:"FreshConnect",country:"India 🇮🇳",lootLost:"$5M",livedYears:"~1 Year",causeTag:"CONFLICT",valueProp:"An AgTech platform trying to connect farmers directly to juice manufacturers to optimize supply chains.",causeOfDeath:"The Ego War. The co-founders were too polite to confront each other. One was too rational, the other too emotional. They built resentment instead of a business.",tldr:"They died because the founders were too polite to have a screaming match."},{rank:9,name:"Howell Market",country:"USA 🇺🇸",lootLost:"$4M",livedYears:"~3 Months",causeTag:"CONFLICT",valueProp:"An online marketplace for gag gifts and novelty items, allowing individual sellers to list products.",causeOfDeath:"The Nepo-Fail. The founder hired friends and family to ease the workload. They treated it like a hobby, did no work, and the founder burned out trying to carry them.",tldr:"Don't hire your cousin unless you're willing to fire your cousin."},{rank:10,name:"SchoolGennie",country:"India 🇮🇳",lootLost:"$3M",livedYears:"~1.5 Years",causeTag:"CONFLICT",valueProp:"ERP software for schools to manage attendance, grades, and communication with parents.",causeOfDeath:"The Copycat Trap. Instead of listening to users, the founders argued about which competitor features to copy. They built a Frankenstein product that did everything poorly.",tldr:"They looked at their competitors so much they forgot to look at their customers."}]},cause_legal:{title:"TOP 10: THE OUTLAWS",subtitle:"They fought the law",slug:"cause_legal",icon:"⚖️",items:[{rank:1,name:"Wirecard",country:"Germany 🇩🇪",lootLost:"$28B",livedYears:"~21 Years",causeTag:"LEGAL",valueProp:"A leading global payment processor and financial services provider that managed electronic transactions for merchants, acting as a gateway for credit cards and alternative payments.",causeOfDeath:"Accounting Fraud. They invented €1.9B in revenue to pump the stock. When auditors asked for the bank receipt, the CEO admitted it never existed.",tldr:"The Enron of Fintech: They made up the money, then sued the journalists who noticed."},{rank:2,name:"Ezubao",country:"China 🇨🇳",lootLost:"$7.6B",livedYears:"~1.5 Years",causeTag:"LEGAL",valueProp:"An online peer-to-peer lending platform that promised retail investors guaranteed high-yield returns by funding large-scale industrial leasing and infrastructure projects.",causeOfDeath:"The Ponzi Scheme. 95% of the projects were fake. The founder used $7.6B of user money to buy gifts, villas, and a pink diamond.",tldr:"A $7.6B robbery disguised as a finance app."},{rank:3,name:"Thodex",country:"Turkey 🇹🇷",lootLost:"$2B",livedYears:"~4 Years",causeTag:"LEGAL",valueProp:"A cryptocurrency exchange that provided a digital platform for users to buy and sell assets, attracting hundreds of thousands of customers with zero-commission trading campaigns.",causeOfDeath:"The Rug Pull. The CEO halted trading due to a cyberattack, then boarded a flight to Albania with $2B of user funds on a USB drive.",tldr:"The CEO went out for cigarettes (and $2 billion) and never came back."},{rank:4,name:"FTX",country:"Bahamas 🇧🇸",lootLost:"$1.8B",livedYears:"~3.5 Years",causeTag:"LEGAL",valueProp:"A major cryptocurrency exchange offering advanced trading products like derivatives and leveraged tokens, positioning itself as a regulated platform for institutional investors.",causeOfDeath:"Embezzlement. SBF used customer deposits as a personal piggy bank to fund his hedge fund (Alameda), buy real estate, and donate to politicians.",tldr:"Effective Altruism turned out to be Effective Embezzlement."},{rank:5,name:"Intarcia",country:"USA 🇺🇸",lootLost:"$1.4B",livedYears:"~25 Years",causeTag:"LEGAL",valueProp:"A biopharmaceutical company that developed a matchstick-sized implantable device designed to deliver continuous Type 2 diabetes medication for up to six months.",causeOfDeath:"The FDA Coverup. The FDA rejected the device for safety risks. Executives hid this from investors to keep raising money. The SEC charged them with fraud.",tldr:"They sold a medical miracle that the FDA had already marked as a medical hazard."},{rank:6,name:"ITT Tech",country:"USA 🇺🇸",lootLost:"$1.4B",livedYears:"~47 Years",causeTag:"LEGAL",valueProp:"A for-profit technical institute offering associate and bachelor’s degree programs in technology and business, marketed as a career-focused alternative to traditional universities.",causeOfDeath:"Predatory Lending. The US Govt cut off their access to federal aid because they were burying students in debt for degrees that employers didn't respect.",tldr:"They sold degrees that cost $80k but were worth less than the paper they were printed on."},{rank:7,name:"Corinthian",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~20 Years",causeTag:"LEGAL",valueProp:"A massive network of for-profit colleges providing vocational training and diploma programs in healthcare and trades, targeting non-traditional students seeking rapid employment.",causeOfDeath:"Falsified Stats. They lied about job placement rates (counting a Taco Bell job as corporate placement) to qualify for government loans.",tldr:"They lied about getting you a job so they could get the government's money."},{rank:8,name:"Zhangmen",country:"China 🇨🇳",lootLost:"$1B",livedYears:"~9 Years",causeTag:"LEGAL",valueProp:"An online education platform providing personalized one-on-one tutoring for K-12 students in China, focusing on academic subject preparation for competitive entrance exams.",causeOfDeath:"Regulatory Sudden Death. The Double Reduction policy banned for-profit tutoring overnight. The government decided their business model was illegal.",tldr:"The government decided their entire industry was illegal on a Tuesday."},{rank:9,name:"Amigo Loans",country:"UK 🇬🇧",lootLost:"$1B",livedYears:"~19 Years",causeTag:"LEGAL",valueProp:"A subprime lender offering guarantor loans to individuals with poor credit, requiring a friend or family member to co-sign and assume full liability for the debt.",causeOfDeath:"The Compensation Crush. Regulators ruled they failed affordability checks. They were drowned by thousands of lawsuits from customers they shouldn't have lent to.",tldr:"They lent money to people who couldn't pay, backed by friends who wouldn't pay."},{rank:10,name:"SmileDirectClub",country:"USA 🇺🇸",lootLost:"$900M",livedYears:"~9 Years",causeTag:"LEGAL",valueProp:"A teledentistry company that manufactured and shipped clear teeth aligners directly to consumers, providing a remote and lower-cost alternative to in-office orthodontic treatment.",causeOfDeath:"Regulatory War. They sued dental boards and forced customers into NDAs to hide bad reviews. Eventually, the debt and legal battles suffocated them.",tldr:"They fought the dentists, the regulators, and the creditors, and lost to all of them."}]},cause_competition:{title:"TOP 10: THE CRUSHED",subtitle:"Good products that got eaten by Google/Facebook/Amazon.",slug:"cause_competition",icon:"🐜",items:[{rank:1,name:"Uber Rush",country:"USA 🇺🇸",lootLost:"$2.5B",livedYears:"~3 Years",causeTag:"COMPETION",valueProp:"The Everything Courier—an API allowing local merchants (florists, dry cleaners) to use Uber drivers for same-day delivery.",causeOfDeath:"The Cannibal. It competed with Uber's own core business. Drivers were delivering burritos instead of people, causing surge pricing for passengers.",tldr:"They accidentally DDOS'd their own taxi service with sandwiches."},{rank:2,name:"SolarWorld",country:"Germany 🇩🇪",lootLost:"$1B",livedYears:"~29 Years",causeTag:"COMPETION",valueProp:"The Mercedes of Solar—high-quality, German-engineered solar panels that promised superior longevity and efficiency.",causeOfDeath:"The Price War. Chinese competitors (subsidized by the state) flooded the market with panels that were 90% as good for 50% of the cost.",tldr:"You can't beat a competitor who doesn't care about making a profit."},{rank:3,name:"Groupon Now",country:"USA 🇺🇸",lootLost:"$950M",livedYears:"~3 Years",causeTag:"COMPETION",valueProp:"Real-Time Deals—a feature to find lunch specials or spa slots available right now based on your GPS location.",causeOfDeath:"The Habit Gap. Users didn't open Groupon spontaneously when hungry; they opened Yelp or Google. The impulse buy behavior never formed.",tldr:"They tried to change human behavior instead of fitting into it."},{rank:4,name:"Jawbone",country:"USA 🇺🇸",lootLost:"$900M",livedYears:"~18 Years",causeTag:"COMPETION",valueProp:"The Cool Wearable—pioneered the designer tech aesthetic with the Jambox speaker and the UP fitness tracker.",causeOfDeath:"Hardware Hell. They had beautiful designs but terrible engineering (bricked devices). Meanwhile, Apple and Fitbit ate the market.",tldr:"Great design can't save a product that stops working after 3 months."},{rank:5,name:"Invision",country:"USA 🇺🇸",lootLost:"$350M",livedYears:"~13 Years",causeTag:"COMPETION",valueProp:"The Design Standard—the original prototyping tool that allowed designers to link static screens together for stakeholder review.",causeOfDeath:"The Browser Disruption. They stayed on desktop (syncing files) while Figma built a multiplayer browser tool. Figma ate their lunch in real-time.",tldr:"They were syncing files while Figma was syncing people."},{rank:6,name:"Tongcheng Life",country:"China 🇨🇳",lootLost:"$300M",livedYears:"~3 Years",causeTag:"COMPETION",valueProp:"Community Group Buying—neighbors pooling orders for bulk groceries, promising massive discounts on fresh food.",causeOfDeath:"The Titan War. Meituan and Pinduoduo entered the market with billions in subsidies. They lowered prices until Tongcheng bled out.",tldr:"Don't start a price war with companies that have infinite money."},{rank:7,name:"RetailMeNot UK",country:"UK 🇬🇧",lootLost:"$300M",livedYears:"~13 Years",causeTag:"COMPETION",valueProp:"The Coupon SEO Farm—a massive aggregator of discount codes relying on high Google rankings to drive traffic.",causeOfDeath:"The Extension Killer. Browser extensions like Honey (acquired by PayPal) auto-applied coupons, making searching for codes obsolete.",tldr:"Google Search traffic is not a moat when the browser does the work for you."},{rank:8,name:"Hike Messenger",country:"India 🇮🇳",lootLost:"$261M",livedYears:"~9 Years",causeTag:"COMPETION",valueProp:"WeChat for India—a messaging app with localized stickers, hidden chat modes, and offline features.",causeOfDeath:"The Network Effect. They had cool features, but everyone's grandma was already on WhatsApp. You can't migrate a social graph that is cemented.",tldr:"Features don't matter if your friends aren't there."},{rank:9,name:"Tintri",country:"USA 🇺🇸",lootLost:"$220M",livedYears:"~10 Years",causeTag:"COMPETION",valueProp:"VM-Aware Storage—enterprise storage boxes specifically designed to make Virtual Machines run faster and smoother.",causeOfDeath:"The Squeeze. They got crushed between the All Flash giants (Pure Storage) and the Hyper-converged giants (Nutanix).",tldr:"They built a better mousetrap just as the mice moved to the cloud."},{rank:10,name:"Zulily",country:"USA 🇺🇸",lootLost:"$253M",livedYears:"~13 Years",causeTag:"COMPETION",valueProp:"Flash Sales for Moms—daily deals on kids' clothes and home goods, creating a treasure hunt shopping experience.",causeOfDeath:"The Logistics Lag. Their model required holding zero inventory, which meant shipping took 2-3 weeks. In an Amazon Prime world, nobody waits that long.",tldr:"You can't compete on price if your shipping speed feels like 1999."}]},cause_product:{title:"TOP 10: THE LEMONS",subtitle:"The tech was vaporware.",slug:"cause_product",icon:"🍋",items:[{rank:1,name:"HSMC",country:"China 🇨🇳",lootLost:"$2B",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The $18B Chip Savior. They promised to build China's first 7nm and 14nm chip foundry to break reliance on the US, hiring top TSMC execs and claiming to own advanced ASML lithography machines to sell the dream to the government.",causeOfDeath:"Vaporware Fraud. The ASML machine they pledged was a mortgaged prop, and they never produced a single chip. The CEO was a former traditional medicine salesman with a GED.",tldr:"The biggest semiconductor scam in history ran on PowerPoint and zero silicon."},{rank:2,name:"Theranos",country:"USA 🇺🇸",lootLost:"$700M",livedYears:"~15 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"One Drop of Blood. They claimed to have invented a mini-lab (The Edison) that could run 200+ complex medical tests on a single finger prick, allowing cheap, painless, and instant diagnostics in every Walgreens.",causeOfDeath:"Scientific Fraud. The physics was impossible. They secretly ran the blood samples on standard Siemens machines while lying to investors, doctors, and patients about the accuracy.",tldr:"She dressed like Steve Jobs but ran the company like a cartel."},{rank:3,name:"Mt. Gox",country:"Japan 🇯🇵",lootLost:"$500M",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Magic Exchange. Originally a card trading site, it became the world's first major Bitcoin exchange, handling ~70% of all global crypto transactions during the early era when buying BTC was nearly impossible.",causeOfDeath:"Incompetence & Hacks. A leaky wallet bug and terrible security let hackers drain 850,000 BTC ($460M then, Billions now) while the CEO was busy coding a café loyalty program.",tldr:"They treated a billion-dollar bank like a hobby project and lost the keys."},{rank:4,name:"Levdeo",country:"China 🇨🇳",lootLost:"$500M",livedYears:"~15 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The King of Old Man Cars. They dominated the low speed electric vehicle (LSEV) market—cheap, license-free plastic cars for rural China—and attempted to use that cash to pivot into manufacturing highway-legal EVs.",causeOfDeath:"Regulatory Sudden Death. The government banned their core product (LSEVs) for safety reasons, and their pivot to real cars failed to raise enough cash to survive the brutally competitive EV price war.",tldr:"You can't upgrade a golf cart company into a Tesla competitor overnight."},{rank:5,name:"Nanosolar",country:"USA 🇺🇸",lootLost:"$450M",livedYears:"~11 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"Printing Solar Like Newspapers. They developed CIGS thin-film technology to print solar cells on aluminum foil, promising a panel that was lighter, flexible, and significantly cheaper to manufacture than heavy glass silicon panels.",causeOfDeath:"The Silicon Crash. They bet that Silicon would stay expensive. When Chinese manufacturing drove Silicon prices down 90%, their cheaper alternative became the expensive option, and the tech became obsolete.",tldr:"They bet against Silicon, and Silicon won the price war by a landslide."},{rank:6,name:"Club Penguin",country:"Canada 🇨🇦",lootLost:"$350M",livedYears:"~12 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The First Safe Metaverse. A snowy virtual world where millions of kids could chat, play minigames, and own Puffles in a strictly moderated environment that parents actually trusted.",causeOfDeath:"The Mobile Force. Disney shut down the beloved desktop web version to force everyone to a new mobile app (Club Penguin Island) which stripped away the community features. Users revolted.",tldr:"Disney murdered a beloved childhood community to force a mobile app download."},{rank:7,name:"Embark",country:"USA 🇺🇸",lootLost:"$300M",livedYears:"~7 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Asset-Light Trucker. Instead of building trucks, they built universal autonomous driving software to retrofit existing fleets, promising a high-margin SaaS model for the logistics industry.",causeOfDeath:"Vaporware. The tech wasn't ready for driverless deployment (still required safety drivers), and when the SPAC market collapsed, they lost the infinite runway needed to fix it.",tldr:"You can't sell Software as a Service if the software drives trucks into ditches."},{rank:8,name:"Daqri",country:"USA 🇺🇸",lootLost:"$275M",livedYears:"~9 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Hard Hat of the Future. An industrial Augmented Reality helmet with thermal vision and blueprint overlays, designed to give construction workers and engineers superpowers on the job site.",causeOfDeath:"Hardware Reality. The helmet was heavy, overheated, and cost $15,000. Construction sites preferred cheap iPads or paper blueprints over heavy sci-fi cosplay that ran out of battery.",tldr:"They built Iron Man helmets for construction workers who just wanted a clipboard."},{rank:9,name:"Juicero",country:"USA 🇺🇸",lootLost:"$120M",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Keurig for Juice. A $400 Wi-Fi connected cold-press machine that squeezed proprietary packs of organic produce, promising the freshest juice without the mess of cleaning a traditional juicer.",causeOfDeath:"The Hand Squeeze. Bloomberg journalists discovered you could squeeze the proprietary packs faster with your bare hands than the $400 machine could, proving the hardware was useless.",tldr:"A $400 rolling pin that required a Wi-Fi connection to squeeze a bag."},{rank:10,name:"Rafter",country:"USA 🇺🇸",lootLost:"$115M",livedYears:"~10 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"Course Materials as a Service. They managed textbook rentals and digital access for colleges, promising to lower costs for students by bundling everything into tuition and handling the logistics for the school.",causeOfDeath:"The Middleman Squeeze. Publishers started selling digital access directly to students and schools, bypassing the rental model entirely. The market for physical textbook logistics evaporated.",tldr:"They were the Blockbuster of textbooks in a Netflix world."}]},cause_unit_econ:{title:"TOP 10: THE MATH PROBLEMS",subtitle:"CAC > LTV. The economics never made sense.",slug:"cause_unit_econ",icon:"➗",items:[{rank:1,name:"WeWork",country:"USA 🇺🇸",lootLost:"$22B",livedYears:"~13 Years",causeTag:"UNIT ECONOMICS",valueProp:"Office Space as a Service. They subleased trendy, beer-filled offices to startups on flexible monthly terms, promising Community rather than just a desk.",causeOfDeath:"Asset Liability Mismatch. They signed 15-year lease obligations (fixed debt) but sold 1-month memberships (variable revenue). When a recession hit, the members left, but the rent was still due.",tldr:"The world's most expensive rental arbitrage."},{rank:2,name:"WM Motor",country:"China 🇨🇳",lootLost:"$5.8B",livedYears:"~8 Years",causeTag:"UNIT ECONOMICS",valueProp:"The EV for Everyone. They aimed to be the Volkswagen of EVs—building affordable, reliable electric SUVs for the mass market, rather than luxury toys.",causeOfDeath:"The Middle Market Squeeze. They didn't have the high margins of Nio or the massive volume of BYD. They died in the Valley of Death where production costs exceeded the sale price per unit.",tldr:"Being average in a price war is a death sentence."},{rank:3,name:"Pluralsight",country:"USA 🇺🇸",lootLost:"$4B",livedYears:"~20 Years",causeTag:"UNIT ECONOMICS",valueProp:"Netflix for Coders. A massive library of video courses to help developers learn new coding languages, sold via enterprise licenses.",causeOfDeath:"The AI Deflation. They took on billions in debt to grow. Then ChatGPT arrived and made learning to code free/commodity. Revenue couldn't cover the interest payments.",tldr:"Lenders took the keys because AI made their product free."},{rank:4,name:"Qoros Auto",country:"China 🇨🇳",lootLost:"$3B",livedYears:"~17 Years",causeTag:"UNIT ECONOMICS",valueProp:"European Quality, Chinese Price. A joint venture (Israel + China) attempting to build the first Chinese car brand that could compete with Audi or BMW on quality.",causeOfDeath:"The Cost of Quality. They spent billions over-engineering the car. It was too expensive for Chinese buyers and too unknown for European buyers. They sold cars at a massive loss to build a brand that never stuck.",tldr:"They built a Mercedes-Benz on a Kia budget and went broke trying to sell it."},{rank:5,name:"Katerra",country:"USA 🇺🇸",lootLost:"$2.6B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Construction in a Box. They wanted to build skyscrapers like iPhones—prefabricating walls in massive factories to lower costs and speed up timelines.",causeOfDeath:"Fixed vs. Variable. Construction is cyclical (variable demand). Factories have high fixed costs. When projects paused (COVID), the factory overhead burned them alive.",tldr:"You can't treat a construction site like an assembly line."},{rank:6,name:"Singulato",country:"China 🇨🇳",lootLost:"$2.4B",livedYears:"~9 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Smartest EV. They raised $2.4B promising an EV with suicide doors and massive screens, focusing on software over manufacturing.",causeOfDeath:"Production Hell. They burned 17B RMB but never set up a functional production line. They relied on contract manufacturers who refused to work when the bills weren't paid.",tldr:"They raised $2.4B and didn't produce a single mass-market car."},{rank:7,name:"Ofo",country:"China 🇨🇳",lootLost:"$2.4B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Yellow Bike. Dockless bike sharing. Scan a QR code, ride for pennies, leave it anywhere.",causeOfDeath:"The Depreciation Disaster. Their bikes cost ~$50 but broke in 2 months. The ride revenue (pennies) never covered the cost of the bike + the army of trucks needed to move them.",tldr:"They tried to scale a business where the asset destroys itself."},{rank:8,name:"Fair.com",country:"USA 🇺🇸",lootLost:"$2.1B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Car Ownership is Dead. A subscription model for used cars. No loans, no commitment, just pay a monthly fee and return the car whenever you want.",causeOfDeath:"The Depreciation Curve. They bought cars (assets) that lost value faster than users paid the subscription fees. The debt on the cars was higher than the income they generated.",tldr:"The car lost value faster than the user paid rent."},{rank:9,name:"Best Express",country:"China 🇨🇳",lootLost:"$2B",livedYears:"~14 Years",causeTag:"UNIT ECONOMICS",valueProp:"Logistics for E-commerce. A massive courier network delivering Alibaba/Taobao packages across China.",causeOfDeath:"The Price War Victim. To compete with J&T Express, they lowered shipping prices to below cost. They were bleeding cash on every package delivered until they were forced to sell the business.",tldr:"They sold dollars for 80 cents to keep market share."},{rank:10,name:"Q-Cells",country:"Germany 🇩🇪",lootLost:"$2B",livedYears:"~13 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Solar King. Once the world's largest solar cell manufacturer, betting on high-efficiency German engineering.",causeOfDeath:"The Commodity Crush. They bet on expensive Silicon. Chinese competitors dropped prices by 40% in a single year. Q-Cells' production cost was higher than the market price of the final product.",tldr:"The market price dropped below their manufacturing cost, and they couldn't stop the factory."}]},sec_fintech:{title:"TOP 10: FINTECH FLOPS",subtitle:"Neo-banks and lending protocols that imploded.",slug:"sec_fintech",icon:"💸",items:[{rank:1,name:"Silicon Valley Bank",country:"USA 🇺🇸",lootLost:"$209B",livedYears:"~40 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Founder's Bank. The only bank that treated startups like royalty, offering venture debt and networking events when traditional banks wouldn't open an account.",causeOfDeath:"Duration Mismatch. They invested short-term deposits into long-term bonds. When rates rose and tech funding dried up, they had to sell the bonds at a loss, triggering a panic.",tldr:"They died because their customers (VCs) have a WhatsApp group and zero loyalty."},{rank:2,name:"Wirecard",country:"Germany 🇩🇪",lootLost:"$28B",livedYears:"~21 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Invisible Layer. A payment processor that promised to handle transactions for the high risk internet (gambling/porn) seamlessly, claiming to be the PayPal of Europe.",causeOfDeath:"Accounting Fiction. They claimed €1.9B was sitting in a Philippine bank account. It wasn't. The CEO admitted the money never existed and the company was a hollow shell.",tldr:"The Enron of Fintech: They made up the money, then sued the journalists who noticed."},{rank:3,name:"Ezubao",country:"China 🇨🇳",lootLost:"$7.6B",livedYears:"~1.5 Years",causeTag:"RAN OUT OF CASH",valueProp:"Guaranteed Wealth. A P2P lending platform that promised retail investors massive, risk-free returns by funding infrastructure projects in China.",causeOfDeath:"The Ponzi. 95% of the investment projects were fake. The founder used $7.6B of user money to buy gifts, luxury villas, and a pink diamond.",tldr:"A $7.6B robbery disguised as a finance app."},{rank:4,name:"Thodex",country:"Turkey 🇹🇷",lootLost:"$2B",livedYears:"~4 Years",causeTag:"LEGAL",valueProp:"Crypto for the People. A Turkish exchange that used aggressive marketing (models, Porsches) to attract 400,000 users looking to hedge against the Lira's inflation.",causeOfDeath:"The Rug Pull. The CEO halted trading due to a cyberattack, then boarded a flight to Albania with $2B of user funds on a hard drive.",tldr:"The CEO went out for cigarettes (and $2 billion) and never came back."},{rank:5,name:"Greensill capital",country:"UK 🇬🇧",lootLost:"$1.7B",livedYears:"~10 Years",causeTag:"UNIT ECONOMICS",valueProp:"Supply Chain Magic. They offered Reverse Factoring, paying suppliers early on behalf of big companies, supposedly smoothing out global trade cash flow.",causeOfDeath:"The Future Invoice. They started lending money against prospective invoices (sales that hadn't happened yet). When insurance firms stopped covering these imaginary bets, the house of cards fell.",tldr:"They lent money against invoices for products that didn't exist yet."},{rank:6,name:"BlockFi",country:"USA 🇺🇸",lootLost:"$1.1B",livedYears:"~5 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Crypto Bank. Allowed users to earn interest on their Bitcoin and borrow cash against their crypto holdings, promising banking grade security.",causeOfDeath:"Contagion. They had massive exposure to FTX and Alameda Research. When FTX collapsed, BlockFi's safe assets were frozen, and they couldn't pay back depositors.",tldr:"They were the safe bank, until they lent all your money to the risky bank."},{rank:7,name:"Amigo Loans",country:"UK 🇬🇧",lootLost:"$1B",livedYears:"~18 Years",causeTag:"LEGAL",valueProp:"Friends with Debts. A subprime lender that offered loans to people with bad credit, provided they could find a friend or family member to guarantee (co-sign) the loan.",causeOfDeath:"Regulatory Crush. The UK regulator (FCA) ruled they failed proper affordability checks. They were drowned by thousands of compensation claims from guarantors who were unfairly targeted.",tldr:"They lent money to people who couldn't pay, backed by friends who wouldn't pay."},{rank:8,name:"Zepz",country:"UK 🇬🇧",lootLost:"$700M",livedYears:"~14 Years",causeTag:"UNIT ECONOMICS",valueProp:"Border-less Cash. A digital cross-border payments giant (owning WorldRemit and Sendwave) focused on making remittance cheaper and faster for migrants.",causeOfDeath:"The Valuation Reality Check. (Not Bankrupt, but Battered). They stalled their IPO indefinitely and cut ~26% of staff as the growth at all costs market vanished. They are the zombie of the unicorn herd.",tldr:"They proved that even unicorns bleed when the free money stops flowing."},{rank:9,name:"GetBack",country:"Poland 🇵🇱",lootLost:"$600M",livedYears:"~6 Years",causeTag:"LEGAL",valueProp:"The Debt Collector. A massive debt purchasing company that bought bad loans from banks and promised high returns to bondholders who funded the purchases.",causeOfDeath:"The Bond Scam. They sold bonds to retail investors using aggressive misselling (claiming they were guaranteed). They were actually running a pyramid scheme to pay off old debts.",tldr:"They sold guaranteed bonds to grandmothers to fund a pyramid scheme."},{rank:10,name:"Mt. Gox",country:"Japan 🇯🇵",lootLost:"$500M",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Original Exchange. Started as a Magic: The Gathering card exchange, it pivoted to become the world's primary Bitcoin exchange, handling 70% of all global traffic.",causeOfDeath:"Incompetence & Hacks. A leaky wallet bug and terrible security let hackers drain 850,000 BTC ($460M then, Billions now) while the CEO was busy coding a café loyalty program.",tldr:"They treated a billion-dollar bank like a hobby project and lost the keys."}]},sec_crypto:{title:"TOP 10: CRYPTO RUGS",subtitle:"Billions in value",slug:"sec_crypto",icon:"📉",items:[{rank:1,name:"FTX",country:"Bahamas 🇧🇸",lootLost:"$1.8B",livedYears:"~3.5 Years",causeTag:"LEGAL",valueProp:"The Safe Exchange. Positioned as the regulated, adult-run exchange for institutional investors, offering advanced derivatives and high-speed trading with a pro interface.",causeOfDeath:"Embezzlement (Theft). The founder (SBF) secretly moved billions of customer deposits to his hedge fund (Alameda) to cover bad gambling bets. When users tried to withdraw, the money wasn't there.",tldr:"Effective Altruism turned out to be Effective Embezzlement."},{rank:2,name:"Celsius network",country:"USA 🇺🇸",lootLost:"$864M",livedYears:"~5 Years",causeTag:"UNIT ECONOMICS",valueProp:"Unbank Yourself. A crypto lending platform that promised 18% APY on deposits, claiming to share profits with users rather than greedy banks.",causeOfDeath:"Risky Yield Farming. They didn't generate 18% yield from safe lending; they were gambling user funds in high-risk DeFi protocols. When the market dipped, they became insolvent and froze withdrawals.",tldr:"They called banks greedy while running a Ponzi scheme in the background."},{rank:3,name:"Coinbase NFT",country:"USA 🇺🇸",lootLost:"$800M",livedYears:"~1 Year",causeTag:"NO MARKET NEED",valueProp:"Social Marketplace. An NFT platform designed to be the Instagram of Crypto, allowing users to comment on and follow others' wallets, aiming to dethrone OpenSea.",causeOfDeath:"Timing Failure. They launched weeks after the global NFT market crashed. They threw a massive launch party for a product nobody wanted to use anymore (generating <$1,000 in volume on some days).",tldr:"They arrived at the gold rush two weeks after the mine collapsed."},{rank:4,name:"Core Scientific",country:"USA 🇺🇸",lootLost:"$600M",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"Industrial Mining. One of the largest Bitcoin miners in North America, hosting thousands of machines in massive data centers to secure the blockchain.",causeOfDeath:"Energy vs. Asset Price. They took on massive debt to buy machines at the peak. When energy prices skyrocketed and Bitcoin's price crashed, it cost them more to mine a coin than the coin was worth.",tldr:"Their electricity bill was higher than their revenue."},{rank:5,name:"Voyager Digital",country:"USA 🇺🇸",lootLost:"$160M",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"Commission-Free Broker. A slick mobile app that made buying crypto as easy as Uber, offering interest on idle assets to attract retail users.",causeOfDeath:"Counterparty Contagion. They lent $650M of customer money to a single hedge fund (Three Arrows Capital) without proper collateral. When 3AC went bust, Voyager instantly died.",tldr:"They lent 60% of their loan book to one guy who gambled it all away."},{rank:6,name:"Krab",country:"South Korea 🇰🇷",lootLost:"$15M",livedYears:"~4 Years",causeTag:"COMPETION",valueProp:"Decentralized Money. An algorithmic stablecoin (UST) that maintained its $1 peg via code and arbitrage incentives, rather than holding actual dollars in a bank.",causeOfDeath:"The Death Spiral. The algorithm failed when a massive sell-off triggered a panic. The system hyper-inflated the supply of Luna to try and save the peg, driving the value to $0.000001 in days.",tldr:"They tried to replace the Federal Reserve with a few lines of code."},{rank:7,name:"Letter",country:"Singapore 🇸🇬",lootLost:"$15M",livedYears:"~10 Years",causeTag:"COMPETION",valueProp:"The Super Cycle Fund. A massive crypto hedge fund that bet on the Super Cycle theory (crypto only goes up), managing billions for other companies.",causeOfDeath:"Leverage Suicide. They borrowed money from everyone (Voyager, Genesis, BlockFi) to bet on long positions. When the market turned, they were margin called into oblivion, taking their lenders down with them.",tldr:"They borrowed billions to bet that the line would only go up."},{rank:8,name:"Blockstamp",country:"India 🇮🇳",lootLost:"$12M",livedYears:"~2 Years",causeTag:"NO MARKET NEED",valueProp:"India's First Choice. A leading Indian crypto exchange that provided a seamless rupee-to-crypto ramp for millions of new Indian investors.",causeOfDeath:"Regulatory Ban. The Reserve Bank of India (RBI) banned banks from dealing with crypto companies. Overnight, Koinex lost its banking rails and could no longer process deposits or withdrawals.",tldr:"The Central Bank pulled the plug and the screen went black."},{rank:9,name:"Koinex",country:"Colombia 🇨🇴",lootLost:"$7M",livedYears:"~3 Years",causeTag:"LEGAL",valueProp:"Crypto Remittances. Used stablecoins to help Venezuelan migrants in Colombia send money back home instantly, bypassing hyperinflation and slow banks.",causeOfDeath:"Adoption Ceiling. The tech worked, but teaching unbanked users to navigate crypto wallets was too expensive. They couldn't scale past the early adopter phase before running out of runway.",tldr:"Great mission, but Grandma using crypto is a very hard user behavior to scale."},{rank:10,name:"Valiu",country:"Estonia 🇪🇪",lootLost:"$6M",livedYears:"~4 Years",causeTag:"LEGAL",valueProp:"Timestamping Truth. A specialized blockchain built to timestamp documents (DNA data, banking records) to prove they hadn't been tampered with.",causeOfDeath:"Feature vs. Product. Timestamping is a feature of Bitcoin/Ethereum, not a standalone business. They built a custom blockchain for a use case that didn't need its own chain.",tldr:"They built an entire highway just to drive one specific car."}]},sec_edtech:{title:"TOP 10: EDTECH DROPOUTS",subtitle:"The post-COVID crash victims.",slug:"sec_edtech",icon:"🎓",items:[{rank:1,name:"Byju's",country:"India 🇮🇳",lootLost:"$6B",livedYears:"~13 Years",causeTag:"RAN OUT OF CASH",valueProp:"The EdTech Empire. The world's most valuable EdTech ($22B), offering gamified learning apps for kids and aggressive 1-on-1 tutoring sales to parents.",causeOfDeath:"The Debt Trap. They spent billions acquiring companies (WhiteHat Jr, Aakash) to hide slowing growth. When the auditors checked the books, the cash was gone and the debt remained.",tldr:"They sold fear to parents and bought growth with debt."},{rank:2,name:"ITT Tech",country:"USA 🇺🇸",lootLost:"$1.1B",livedYears:"~47 Years",causeTag:"LEGAL",valueProp:"Career-Focused Degrees. A massive for-profit college chain promising working adults a fast track to high-paying jobs in IT and electronics.",causeOfDeath:"Predatory Lending. The US Govt cut off their access to federal aid because they were burying students in debt for degrees that employers didn't respect.",tldr:"They sold degrees that cost $80k but were worth less than the paper they were printed on."},{rank:3,name:"Udacity",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~13 Years",causeTag:"NO MARKET NEED",valueProp:"The University Killer. The original MOOC that promised to replace college with Nanodegrees co-created by Google and Facebook, focusing on job-ready skills.",causeOfDeath:"Unit Economics. Education requires services (grading/mentorship), not just content. They couldn't make the economics of human grading work at venture scale and sold for scraps.",tldr:"They tried to automate the professor but ended up just building a video library."},{rank:4,name:"Corinthian",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~20 Years",causeTag:"LEGAL",valueProp:"Vocational Training. A network of for-profit colleges (Everest College) targeting low-income students with aggressive ads for healthcare and trade programs.",causeOfDeath:"Falsified Stats. They lied about job placement rates (counting a Taco Bell job as corporate placement) to qualify for government loans.",tldr:"They lied about getting you a job so they could get the government's money."},{rank:5,name:"2U",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~16 Years",causeTag:"RAN OUT OF CASH",valueProp:"The OPM Giant. They helped elite universities (Harvard/Yale) put their degrees online, taking a massive ~60% cut of the tuition revenue.",causeOfDeath:"Debt Overload. They took on massive debt to acquire edX just as demand for expensive online degrees crashed. The revenue share model became toxic to universities.",tldr:"They became the landlord of online education right before the housing crash."},{rank:6,name:"OneSmart Edu",country:"China 🇨🇳",lootLost:"$500M",livedYears:"~14 Years",causeTag:"LEGAL",valueProp:"Premium Tutoring. A high-end K-12 tutoring giant in China, charging premium prices for elite exam preparation.",causeOfDeath:"Regulatory Sudden Death. The Double Reduction policy banned for-profit tutoring overnight. The government decided their business model was illegal on a Tuesday.",tldr:"The government decided their entire industry was illegal on a Tuesday."},{rank:7,name:"WhiteHat Jr",country:"India 🇮🇳",lootLost:"$300M",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"Coding for Kids. Promised to turn 6-year-olds into app developers, using aggressive ads claiming your child would be the next Bill Gates.",causeOfDeath:"CAC > LTV. They spent more on ads than they made in tuition. Byju's bought them for $300M, but the growth at all costs model burned cash until it was shut down.",tldr:"They spent $300 to acquire a customer who paid $200."},{rank:8,name:"Knewton",country:"USA 🇺🇸",lootLost:"$182M",livedYears:"~11 Years",causeTag:"COMPETION",valueProp:"The Robot Tutor. Claimed their adaptive learning algorithm was so good it could predict what a student would fail before they took the test.",causeOfDeath:"The Pivot Fail. The platform model failed, so they tried to become a textbook publisher. They burned $180M and sold for just $17M.",tldr:"They spent $180M building a robot tutor that nobody wanted to hire."},{rank:9,name:"AltSchool",country:"USA 🇺🇸",lootLost:"$175M",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Micro-School. Founded by a Google exec to build a network of tiny, tech-enabled schools where cameras tracked every student interaction.",causeOfDeath:"Scaling Humans. It turns out running physical schools is incredibly hard and low margin. They burned $175M trying to reinvent the classroom, then pivoted to just selling software.",tldr:"They realized that children are not users you can A/B test."},{rank:10,name:"InBloom",country:"USA 🇺🇸",lootLost:"$100M",livedYears:"~3 Years",causeTag:"LEGAL",valueProp:"The Data Lake. Backed by the Gates Foundation to store all student data (grades, attendance, discipline) in one massive cloud database to help personalize learning.",causeOfDeath:"Privacy Panic. Parents were terrified of a single database holding their child's entire life history. Public outcry forced every state to withdraw from the partnership.",tldr:"They tried to build Big Brother for kindergarteners."}]},sec_health:{title:"TOP 10: BIOHAZARDS",subtitle:"Biotech bets and digital health apps that flatlined.",slug:"sec_health",icon:"☣️",items:[{rank:1,name:"Intarcia",country:"USA 🇺🇸",lootLost:"$1.4B",livedYears:"~25 Years",causeTag:"LEGAL",valueProp:"The Matchstick Cure. Developed a tiny implantable pump (ITCA 650) the size of a matchstick that promised to deliver Type 2 diabetes medication continuously for 6 months.",causeOfDeath:"FDA Fraud. The FDA rejected the device due to safety risks. Executives hid this rejection letter from investors to keep the funding rounds going ($1.7B raised).",tldr:"They sold a medical miracle that the FDA had already marked as a medical hazard."},{rank:2,name:"Babylon Health",country:"UK 🇬🇧",lootLost:"$1.2B",livedYears:"~10 Years",causeTag:"UNIT ECONOMICS",valueProp:"GP in Your Pocket. An AI-powered app that claimed to diagnose patients better than human doctors, aiming to replace expensive GP visits with a chatbot.",causeOfDeath:"SPAC & Burn. They went public via SPAC at a $4.2B valuation without a sustainable business model. The AI wasn't accurate enough to replace humans, and the cash ran out.",tldr:"They tried to replace doctors with a chatbot, but the chatbot couldn't sign the checks."},{rank:3,name:"SmileDirectClub",country:"USA 🇺🇸",lootLost:"$900M",livedYears:"~9 Years",causeTag:"LEGAL",valueProp:"DIY Orthodontics. Shipped clear teeth aligners directly to consumers for 60% less than Invisalign, allowing users to skip the orthodontist visits entirely.",causeOfDeath:"The War on Dentists. They fought a 3-front war against regulators, dental boards, and debt. When interest rates rose, their customer financing model collapsed.",tldr:"They fought the dentists, the regulators, and the creditors, and lost to all of them."},{rank:4,name:"Theranos",country:"USA 🇺🇸",lootLost:"$700M",livedYears:"~15 Years",causeTag:"LEGAL",valueProp:"One Drop of Blood. Claimed to run 200+ complex lab tests (cancer, diabetes) on a single finger-prick of blood using a proprietary Edison machine.",causeOfDeath:"The Physics Lie. The technology was physically impossible. They secretly ran tests on standard Siemens machines while lying to the world.",tldr:"She dressed like Steve Jobs but ran the company like a cartel."},{rank:5,name:"Forward Health",country:"USA 🇺🇸",lootLost:"$650M",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The AI CarePod. A futuristic, high-tech primary care clinic (and later, self-service CarePods) that aimed to turn going to the doctor into an Apple Store experience.",causeOfDeath:"Hardware Reality. The CarePods (self-service kiosks) were expensive to build and frequently broke. Patients didn't want to be locked in a box for a blood draw. Shut down Nov 2024.",tldr:"They built an Apple Store for healthcare, but forgot that sick people need empathy, not iPads."},{rank:6,name:"Pear Therapeutics",country:"USA 🇺🇸",lootLost:"$315M",livedYears:"~10 Years",causeTag:"UNIT ECONOMICS",valueProp:"Prescription Apps. The first company to get FDA approval for Digital Therapeutics—software apps prescribed by doctors to treat addiction and insomnia.",causeOfDeath:"The Payer Gap. They got the FDA approval, but insurance companies refused to pay for an app. Doctors didn't know how to prescribe code.",tldr:"They built the world's first prescription video game, but nobody knew how to pay for it."},{rank:7,name:"DrKoop.com",country:"USA 🇺🇸",lootLost:"$130M",livedYears:"~5 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Celebrity Doctor. A massive medical advice site built entirely on the personal brand of former US Surgeon General C. Everett Koop during the Dotcom bubble.",causeOfDeath:"Trust vs. Revenue. They burned through $88M trying to turn trust into ad revenue. When the bubble burst, users went to WebMD (which had better utility).",tldr:"Turns out, The Surgeon General is not a defensible business moat."},{rank:8,name:"Arivale",country:"USA 🇺🇸",lootLost:"$50M",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"Scientific Wellness. A high-end coaching service that combined your DNA, gut microbiome, and blood data to create a hyper-personalized health plan for $3,500.",causeOfDeath:"The Price Ceiling. The cost to run the tests was too high. They lost money on every customer, and the market for $3,500 diet advice was tiny.",tldr:"They tried to sell immortality to people who just wanted to lose 5 pounds."},{rank:9,name:"HealthSpot",country:"USA 🇺🇸",lootLost:"$48M",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Telehealth Kiosk. Installed massive, enclosed telemedicine booths in Rite-Aid pharmacies so patients could talk to a doctor on a screen in private.",causeOfDeath:"The Box Problem. Patients hated sitting in a claustrophobic box in a pharmacy. The maintenance costs of cleaning/staffing the kiosks were astronomical.",tldr:"They put a doctor in a box, but forgot to think about the patient outside the box."},{rank:10,name:"Maven",country:"USA 🇺🇸",lootLost:"$45M",livedYears:"~3 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Corporate Savior. A joint venture by Amazon, JPMorgan, and Berkshire Hathaway designed to fix healthcare for their 1.2M combined employees.",causeOfDeath:"Leverage Failure. Even with 1.2M employees, they lacked the leverage to force hospitals to lower prices. The three giants couldn't agree on a strategy.",tldr:"Three billionaires walked into a bar to fix healthcare, and realized the hospital owned the bar."}]},sec_hardware:{title:"TOP 10: HARDWARE BRICKS",subtitle:"IoT",slug:"sec_hardware",icon:"🧱",items:[{rank:1,name:"Northvolt",country:"Sweden 🇸🇪",lootLost:"$15B",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Green Gigafactory. Aimed to be Europe's first homegrown battery champion, producing the world's greenest lithium-ion cells to break the continent's dependence on Asian manufacturers like CATL and BYD.",causeOfDeath:"Production Hell. They raised $15B+ but struggled with terrible yield rates (defect levels). They couldn't ramp up production fast enough to fulfill contracts for BMW and Scania, leading to a liquidity crisis.",tldr:"You can't copy-paste a Gigafactory just because you have the blueprints."},{rank:2,name:"oneweb",country:"UK 🇬🇧",lootLost:"$3.4B",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"Internet from Space. Planned a massive constellation of 648 low-earth orbit (LEO) satellites to provide high-speed, low-latency broadband to governments and remote regions, competing directly with SpaceX's Starlink.",causeOfDeath:"The CAPEX Cliff. Building satellites is capital-intensive. They ran out of cash in March 2020, right before the finish line, because the markets froze during the pandemic onset. (Saved by UK Gov, but original equity = $0).",tldr:"They ran out of money 74 satellites short of a working product."},{rank:3,name:"Katerra",country:"USA 🇺🇸",lootLost:"$2.6B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Construction as a Product. Promised to vertically integrate the entire construction supply chain—from architectural design to material manufacturing—assembling buildings like iPhones in massive, automated factories.",causeOfDeath:"Fixed Cost Trap. Construction demand is cyclical (variable), but factories have high overhead (fixed). When projects paused during COVID, the factory costs burned them alive while revenue hit zero.",tldr:"You can't treat a construction site like an assembly line."},{rank:4,name:"Singulato",country:"China 🇨🇳",lootLost:"$2.4B",livedYears:"~9 Years",causeTag:"UNIT ECONOMICS",valueProp:"The IoT Car. A Chinese EV startup that focused heavily on software and smart features, promising a futuristic SUV with suicide doors and massive screens that functioned as an IoT device on wheels.",causeOfDeath:"Vaporware Production. They burned through $2.4B without ever setting up a functional production line. They relied on contract manufacturers who eventually refused to work when the bills weren't paid.",tldr:"They raised $2.4B and didn't produce a single mass-market car."},{rank:5,name:"HSMC",country:"China 🇨🇳",lootLost:"$2B",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Chip Savior. Claimed to be building China's most advanced 7nm and 14nm semiconductor foundry to secure national chip independence, hiring top industry talent and boasting about owning advanced lithography tools.",causeOfDeath:"The Great Fraud. The ASML machine they pledged to investors was actually a mortgaged prop. They never produced a single chip. The CEO was a former traditional medicine salesman with a GED.",tldr:"The biggest semiconductor scam in history ran on PowerPoint and zero silicon."},{rank:6,name:"Zeku",country:"China 🇨🇳",lootLost:"$1.4B",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"Custom Silicon. The chip design arm of smartphone giant Oppo, tasked with building custom high-end SoCs and image signal processors (MariSilicon) to differentiate their phones from competitors like Apple and Samsung.",causeOfDeath:"Strategic Retreat. As global smartphone sales slumped, Oppo decided they couldn't afford the billions required to maintain a custom chip division. They shut it down overnight, firing 3,000 engineers.",tldr:"Building chips is a luxury hobby that gets cut when phone sales drop."},{rank:7,name:"JOLED",country:"Japan 🇯🇵",lootLost:"$1B",livedYears:"~8 Years",causeTag:"UNIT ECONOMICS",valueProp:"Printed Screens. Created to commercialize printed OLED technology—a manufacturing method promised to be cheaper and more efficient than traditional evaporation methods—targeting high-end monitors and medical displays.",causeOfDeath:"Scale & Yield. They couldn't achieve the scale or cost-efficiency needed to compete with Korean giants (Samsung/LG). The tech was brilliant, but the business model couldn't survive the capital requirements.",tldr:"Great science project, terrible business against Korean giants."},{rank:8,name:"FCNT",country:"Japan 🇯🇵",lootLost:"$1B",livedYears:"~5 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Senior Phone. A spin-off from Fujitsu that specialized in durable smartphones and the Raku-Raku series designed specifically for seniors, holding a unique niche in Japan's aging mobile market.",causeOfDeath:"Currency Crisis. The crashing Yen combined with soaring chip costs destroyed their margins. They couldn't raise prices on their price-sensitive elderly customer base and filed for bankruptcy.",tldr:"A niche phone for grandmothers couldn't survive a global supply chain crisis."},{rank:9,name:"Better Place",country:"Israel 🇮🇱",lootLost:"$850M",livedYears:"~6 Years",causeTag:"NO MARKET NEED",valueProp:"Battery Swapping. Proposed a network of automated switching stations that could swap an EV battery in minutes, eliminating range anxiety by treating batteries like fuel tanks rather than fixed parts.",causeOfDeath:"Ecosystem Lock-in. They required auto manufacturers to redesign their entire chassis to fit Better Place's batteries. Only Renault agreed. You can't build a network if only one car fits the plug.",tldr:"They tried to be the Apple of cars without building the car."},{rank:10,name:"Arrival",country:"UK 🇬🇧",lootLost:"$660M",livedYears:"~9 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Micro-factory. Attempted to reinvent auto manufacturing by ditching the traditional assembly line in favor of Micro-factories—small, localized production cells run by robots that could be deployed anywhere in the world.",causeOfDeath:"Engineering Hubris. It turns out assembly lines exist for a reason. The micro-factory concept was harder to automate than expected, and they burned all their cash trying to make the robots work.",tldr:"Robots don't buy buses."}]},sec_saas_b2b:{title:"TOP 10: SAAS GRAVES (B2B)",subtitle:"Enterprise tools that nobody wanted to pay for.",slug:"sec_saas_b2b",icon:"👔",items:[{rank:1,name:"Pluralsight",country:"USA 🇺🇸",lootLost:"$4B",livedYears:"~20 Years",causeTag:"UNIT ECONOMICS",valueProp:"Netflix for Coders. A massive library of high-quality video courses helping enterprise developers learn new frameworks (React, Python), sold via expensive corporate licenses.",causeOfDeath:"The AI Deflation. They took on $1.5B+ in debt to grow. Then ChatGPT arrived and made learning to code feel like a commodity. The product became less valuable just as the interest payments exploded.",tldr:"Lenders took the keys because learning to code became free overnight."},{rank:2,name:"Hopin",country:"UK/USA 🇬🇧",lootLost:"$1.1B",livedYears:"~5 Years",causeTag:"NO MARKET NEED",valueProp:"The Virtual Venue. The first platform that actually felt like a conference—complete with networking roulette, main stages, and expo halls—allowing millions to attend events remotely during the pandemic.",causeOfDeath:"Feature vs. Product. It was a temporary utility, not a behavior shift. When the world reopened, attending a conference from your bedroom went from a necessity to a nightmare. The $7.7B valuation evaporated.",tldr:"The fastest unicorn in history became a zombie the moment the masks came off."},{rank:3,name:"Zovio",country:"USA 🇺🇸",lootLost:"$400M",livedYears:"~18 Years",causeTag:"LEGAL",valueProp:"The OPM Pivot. A controversial for-profit college operator (Ashford University) that tried to rebrand itself as a respectable software provider (Online Program Manager) for public universities like U of Arizona.",causeOfDeath:"The Reputation Trap. You can't just change your logo to hide fraud. They were hit with $22M in fines for lying to students about job prospects, which scared off their university partners and forced liquidation.",tldr:"You can change the name on the building, but you can't outrun a fraud investigation."},{rank:4,name:"Invision",country:"USA 🇺🇸",lootLost:"$350M",livedYears:"~13 Years",causeTag:"COMPETION",valueProp:"The Design Standard. The original prototyping giant that allowed design teams to link static images into clickable mockups, becoming the default tool for stakeholder reviews for a decade.",causeOfDeath:"The Browser Disruption. They focused on syncing static files while Figma built a multiplayer browser tool. Designers stopped presenting work and started collaborating on it, leaving InVision in the dust.",tldr:"They were syncing files while Figma was syncing people."},{rank:5,name:"Zilingo",country:"Singapore 🇸🇬",lootLost:"$340M",livedYears:"~7 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Fashion Supply Chain. A B2B marketplace connecting Southeast Asian merchants directly to factories, promising to digitize the dusty, manual supply chain using AI and credit scoring.",causeOfDeath:"The Theranos of Fashion. The digitization was mostly fake. They booked revenue from transactions that never happened to pump their valuation, suspended the CEO, and collapsed under fraud investigations.",tldr:"The AI in their supply chain turned out to be just Excel spreadsheets and lies."},{rank:6,name:"Videology",country:"USA 🇺🇸",lootLost:"$207M",livedYears:"~11 Years",causeTag:"COMPETION",valueProp:"TV for the Internet. An early AdTech giant that helped TV agencies buy digital video ads programmatically, attempting to bridge the massive gap between traditional TV commercials and the internet.",causeOfDeath:"The Middleman Squeeze. They were too dependent on ad agencies (GroupM). When Google and Facebook built their own walled gardens for video, agencies cut out the middleman to save margin.",tldr:"They tried to be the gatekeeper of video ads, but Google just walked around the wall."},{rank:7,name:"TellApart",country:"USA 🇺🇸",lootLost:"$181M",livedYears:"~6 Years",causeTag:"COMPETION",valueProp:"The Prediction Engine. A predictive marketing tool that helped retailers track users across devices to serve hyper-targeted ads (retargeting), famously acquired by Twitter for $530M+.",causeOfDeath:"Death by Acquisition. This wasn't a business failure, but a product murder. Twitter bought them for the engineering talent/code, then deprecated the product to build their own ad stack. The brand ceased to exist.",tldr:"Twitter bought the car just to strip it for parts."},{rank:8,name:"Bitwise",country:"USA 🇺🇸",lootLost:"$158M",livedYears:"~10 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Tech Hub Mirage. Promised to turn Fresno, California into a Silicon Valley by training marginalized workers to code and renovating old buildings to house them.",causeOfDeath:"The Real Estate Ponzi. They weren't a tech company; they were a bad real estate developer. They borrowed millions against buildings they didn't even own to cover payroll. The founders are now in prison.",tldr:"They used Diversity & Inclusion as a cover story for a classic Ponzi scheme."},{rank:9,name:"Rafter",country:"USA 🇺🇸",lootLost:"$115M",livedYears:"~10 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"Course Materials as a Service. They managed the complex logistics of textbook rentals and access codes for colleges, promising to lower costs for students by bundling everything into tuition.",causeOfDeath:"The Publisher squeeze. Textbook publishers realized they didn't need a middleman. They started selling digital access codes directly to students, bypassing Rafter and destroying their margins.",tldr:"They were the Blockbuster of textbooks in a Netflix world."},{rank:10,name:"OpTier",country:"USA/Israel 🇺🇸",lootLost:"$112M",livedYears:"~9 Years",causeTag:"COMPETION",valueProp:"The APM Pioneer. Pioneered Application Performance Monitoring—software that helped enterprises track business transactions across their messy, complex IT stacks to find bottlenecks.",causeOfDeath:"The Cloud Miss. They were great at monitoring old-school on-premise servers. But AppDynamics and New Relic built better tools for the cloud. SAP acquired OpTier for scraps and buried it.",tldr:"They built a better mousetrap just as the mice moved to the cloud."}]},sec_saas_b2c:{title:"TOP 10: CHURN CITY (B2C)",subtitle:"Consumer apps that couldn't retain users.",slug:"sec_saas_b2c",icon:"📉",items:[{rank:1,name:"Stadia",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~3 Years",causeTag:"RAN OUT OF CASH",valueProp:"Console-Free Gaming. Google promised 4K gaming on any screen instantly, claiming their Negative Latency AI could predict your button presses before you made them.",causeOfDeath:"The Business Model Mismatch. They made you buy the hardware (controller), pay a monthly sub, and buy the games at full price. Gamers refused to pay 3x for games they didn't own.",tldr:"Google built a Ferrari engine and put it inside a toll booth that nobody wanted to pay for."},{rank:2,name:"Frank",country:"USA 🇺🇸",lootLost:"$175M",livedYears:"~6 Years",causeTag:"LEGAL",valueProp:"The Student Aid Savior. A platform simplifying the FAFSA financial aid process for students. They claimed to have 4.25 million users to secure a $175M acquisition by JPMorgan.",causeOfDeath:"The Excel Fraud. They only had ~300k users. The founder paid a data scientist $18,000 to invent 4 million fake students in a spreadsheet to fool JPMorgan's due diligence.",tldr:"The $175M acquisition that turned out to be a single CSV file of fake names."},{rank:3,name:"Vessel",country:"USA 🇺🇸",lootLost:"$134M",livedYears:"~3 Years",causeTag:"COMPETION",valueProp:"The YouTube VIP Lane. Founded by the CEO of Hulu, they charged users $3/month to watch YouTube stars' videos 72 hours before they went public.",causeOfDeath:"The Ecosystem Lock. YouTubers took the check but hated the friction. Fans refused to leave the YouTube comments section just to save 3 days. Verizon bought it and killed it.",tldr:"They tried to put a toll booth on the free internet."},{rank:4,name:"Rdio",country:"USA 🇺🇸",lootLost:"$125M",livedYears:"~5 Years",causeTag:"COMPETION",valueProp:"Design-First Streaming. The designer's choice for music. It had the most beautiful UI, the best social features, and the cleanest algorithm before Spotify took over the world.",causeOfDeath:"Distribution > Design. They refused to offer a Free Tier for too long. Spotify used Free to acquire the world, while Rdio died trying to protect the sanctity of the album art.",tldr:"The most beautiful music app that nobody could hear because they were all on Spotify."},{rank:5,name:"Blade (Shadow)",country:"France 🇫🇷",lootLost:"$110M",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Cloud PC. For $12.99/mo, they gave you a high-end Windows gaming PC streamed to your laptop. It worked like magic... until the bill arrived.",causeOfDeath:"Unit Economics Suicide. They rented out $2,000 GPUs for the price of a Netflix subscription. When the GPU shortage hit, their hardware costs exploded while their pricing remained flat.",tldr:"They rented out Ferraris for the price of a bus ticket."},{rank:6,name:"Hooq",country:"Singapore 🇸🇬",lootLost:"$95M",livedYears:"~5 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Asian Netflix. A massive joint venture between Singtel, Sony, and Warner Bros to capture the Southeast Asian streaming market before Netflix arrived.",causeOfDeath:"The Parent Trap. Owned by three giants who couldn't agree. They burned cash on Hollywood content when locals wanted Korean Dramas. When COVID hit, the parents cut the allowance.",tldr:"Three billionaires started a streaming service and forgot to ask what the locals actually watch."},{rank:7,name:"Neeva",country:"USA 🇺🇸",lootLost:"$77M",livedYears:"~4 Years",causeTag:"NO MARKET NEED",valueProp:"Ad-Free Search. Founded by the guy who ran Google Ads, promising a private, subscription-only search engine that never tracked you.",causeOfDeath:"The Free Problem. They proved that people say they care about privacy, but they vote with their wallets. 99.9% of humans will accept surveillance if it saves them $5/month.",tldr:"They tried to sell water to people who were used to drinking from a free firehose."},{rank:8,name:"Hipmunk",country:"USA 🇺🇸",lootLost:"$55M",livedYears:"~10 Years",causeTag:"COMPETION",valueProp:"Agony-Free Travel. The first travel site to sort flights by Agony (duration + price + stops) and visualize trips on a timeline, creating a cult following among frequent flyers.",causeOfDeath:"Strategic Murder. Acquired by SAP Concur, who didn't care about the cute chipmunk or the consumer interface. They stripped the data for their corporate tool and shut down the site.",tldr:"They built the best UI in travel, and a boring corporate expense software bought it to kill it."},{rank:9,name:"Ask Jeeves",country:"USA 🇺🇸",lootLost:"$50M",livedYears:"~14 Years",causeTag:"COMPETION",valueProp:"The Natural Language Butler. The first engine that let you ask Why is the sky blue? instead of typing keywords. It was the internet's concierge.",causeOfDeath:"The PageRank War. They focused on Natural Language marketing while Google focused on Backlink math. Google's results were simply 10x better, and Jeeves became a toolbar malware joke.",tldr:"A polite butler who couldn't find the library."},{rank:10,name:"Thread",country:"UK 🇬🇧",lootLost:"$40M",livedYears:"~10 Years",causeTag:"UNIT ECONOMICS",valueProp:"AI Stylist. You took a quiz, and their AI (plus human stylists) recommended outfits from millions of items. It was Stitch Fix without the inventory risk.",causeOfDeath:"The Algorithm Acquisition. They struggled to make the unit economics work on pure dropshipping. M&S (Marks & Spencer) bought the IP just to integrate the outfit recommendation code into their own site.",tldr:"M&S bought the brain, kept the code, and threw the rest of the company in the bin."}]},sec_social:{title:"TOP 10: SOCIAL GHOST TOWNS",subtitle:"Apps that tried to kill Twitter and Instagram.",slug:"sec_social",icon:"👻",items:[{rank:1,name:"Vice Media",country:"Canada 🇨🇦",lootLost:"$1.4B",livedYears:"~29 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Empire of Cool. News for people who hate news. They sent reporters on acid to war zones and built a $5.7B brand on counter-culture video content for Millennials.",causeOfDeath:"The Pivot to Nowhere. They took massive PE money (TPG) to pivot to Cable TV just as cable died. They spent lavishly on brand (Shane Smith's $300k dinners) while the ad market collapsed beneath them.",tldr:"They sold Counter-Culture to corporate advertisers, and eventually, nobody bought either."},{rank:2,name:"Panda TV",country:"China 🇨🇳",lootLost:"$200M",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Billionaire's Toy. The Twitch of China, founded by Wang Sicong (son of China's richest man). They poached the world's top gamers with blank checks to stream exclusively on Panda.",causeOfDeath:"The Rich Kid Syndrome. They burned cash like it was confetti, overpaying streamers who had zero loyalty. When the father (Wanda Group) cut off the son's allowance, the servers went dark.",tldr:"You can buy streamers, but you can't buy a business model."},{rank:3,name:"Mobli",country:"Israel 🇮🇱",lootLost:"$86M",livedYears:"~6 Years",causeTag:"COMPETION",valueProp:"The Celebrity Instagram. A photo-sharing app backed by Leonardo DiCaprio, Tobey Maguire, and Carlos Slim. They introduced Visual Search and filters before it was cool.",causeOfDeath:"The VIP Trap. They paid celebrities to post, but couldn't pay normal users to care. Users realized the community was just a paid marketing stunt for Hollywood actors.",tldr:"They thought Leonardo DiCaprio could save them from product-market fit."},{rank:4,name:"Quora Credits",country:"USA 🇺🇸",lootLost:"$85M",livedYears:"~1 Year",causeTag:"NO MARKET NEED",valueProp:"The Knowledge Market. A virtual currency system intended to pay experts for answers and let users bounty difficult questions, turning Q&A into an economy.",causeOfDeath:"The Commodification of Passion. It transactionalized social capital. Users stopped writing for the love of teaching because they were waiting to be paid in fake internet points.",tldr:"They tried to turn a dinner party conversation into a flea market transaction."},{rank:5,name:"Path",country:"USA 🇺🇸",lootLost:"$77M",livedYears:"~8 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Anti-Facebook. A beautiful, intimate network limited to your 50 (later 150) closest friends. It pioneered Reactions and staying small on purpose.",causeOfDeath:"The Privacy Paradox. To grow their private network, they uploaded users' contact lists without permission (the Spam Scandal). They violated their core promise of trust to chase growth.",tldr:"They promised intimacy, then spammed your entire phone book to get it."},{rank:6,name:"Yik Yak",country:"USA 🇺🇸",lootLost:"$73M",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Campus Bathroom Wall. An anonymous, location-based bulletin board. You could see what people within 5 miles were saying without knowing who they were.",causeOfDeath:"The Bully Algorithm. It became a weapon for cyberbullying. When they removed anonymity (adding handles) to stop the hate speech/suicides, the users evaporated overnight.",tldr:"The only feature users wanted was the one that made it toxic."},{rank:7,name:"Trell",country:"India 🇮🇳",lootLost:"$60M",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Pinterest for India. A Social Commerce platform where users shared lifestyle videos (makeup, cooking) and could buy the products tagged in the clips.",causeOfDeath:"The Metric Fraud. A forensic audit revealed they used bots to inflate user numbers and round-tripped money to fake their revenue. The next unicorn was a spreadsheet of lies.",tldr:"The influencers were fake, the revenue was fake, but the forensic audit was real."},{rank:8,name:"BranchOut",country:"USA 🇺🇸",lootLost:"$46M",livedYears:"~5 Years",causeTag:"COMPETION",valueProp:"LinkedIn on Facebook. A professional networking layer built inside Facebook, allowing you to find jobs through your friends without leaving the fun app.",causeOfDeath:"The Growth Hack Trap. They grew by tricking users into spamming their friends with invites. It worked until Facebook realized they were annoying the user base and shut off their API access.",tldr:"They built a business on a rented lawn, and the landlord evicted them."},{rank:9,name:"GeoCities",country:"USA 🇺🇸",lootLost:"$45M",livedYears:"~15 Years",causeTag:"COMPETION",valueProp:"The Neighborhoods. The original Home on the web. You picked a neighborhood (SiliconValley, Hollywood) and built a shrine to your hobbies with GIFs and MIDI music.",causeOfDeath:"Corporate Sterilization. Yahoo bought it for $3.6B and tried to standardize it to sell banner ads. They killed the community vibe by enforcing generic URLs and Terms of Service.",tldr:"Yahoo bought a vibrant city and turned it into a sterile shopping mall."},{rank:10,name:"Tout",country:"USA 🇺🇸",lootLost:"$40M",livedYears:"~7 Years",causeTag:"COMPETION",valueProp:"Vine before Vine. A platform for 15-second video status updates. They had the tech, the patents, and huge backers (WWE), launching years before TikTok.",causeOfDeath:"The Social Graph Gap. They were a tool (video hosting) trying to be a network. When Instagram added video, they had the social graph (friends) already. Tout was an island.",tldr:"Nobody wants to post a video to an empty room."}]},sec_proptech:{title:"TOP 10: PROPTECH CRASHES",subtitle:"The WeWork wannabes.",slug:"sec_proptech",icon:"🏘️",items:[{rank:1,name:"View",country:"USA 🇺🇸",lootLost:"$2B",livedYears:"~17 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Smart Window. They manufactured Dynamic Glass that electronically tinted to block glare and heat, promising to turn every office window into a smart device that saved energy and improved employee wellness.",causeOfDeath:"The Hardware Tax. Manufacturing smart glass at scale is excruciatingly expensive. They burned $2B+ dealing with manufacturing defects and warranty claims, while the price was too high for standard developers.",tldr:"They spent $2B trying to reinvent the curtain."},{rank:2,name:"Prodigy Network",country:"USA 🇺🇸",lootLost:"$690M",livedYears:"~16 Years",causeTag:"UNIT ECONOMICS",valueProp:"Democratized Skyscrapers. The pioneer of Real Estate Crowdfunding. They allowed dentists and lawyers to invest as little as $50k to own a piece of a Manhattan luxury hotel, bypassing traditional REITs.",causeOfDeath:"The Ponzi Pivot. The returns weren't coming from the buildings; they were coming from new investors. The founder used the funds to maintain a lavish lifestyle until the lawsuits piled up and the portfolio froze.",tldr:"They sold the dream of being a real estate tycoon to people who couldn't afford the loss."},{rank:3,name:"Knotel",country:"USA 🇺🇸",lootLost:"$600M",livedYears:"~5 Years",causeTag:"UNIT ECONOMICS",valueProp:"WeWork for Grownups. They positioned themselves as the Anti-WeWork, ignoring freelancers to sell Agile Headquarters directly to Fortune 500s. No beer taps, just flexible enterprise leases.",causeOfDeath:"The Arbitrage Collapse. They had the same fatal flaw as WeWork (Long-term leases, Short-term customers). When COVID hit, their enterprise clients simply exercised their flexibility to cancel contracts, leaving Knotel with the rent bill.",tldr:"They mocked WeWork's culture but copied WeWork's fatal math."},{rank:4,name:"Veev",country:"USA 🇺🇸",lootLost:"$600M",livedYears:"~15 Years",causeTag:"UNIT ECONOMICS",valueProp:"The iPhone Home. A vertically integrated home builder that prefabricated walls including plumbing, electric, and sensors in a factory, promising to assemble a luxury home on-site in days, not months.",causeOfDeath:"The Capital Crunch. Reinventing construction requires billions in R&D before you sell a single house. When the VC market turned in 2023, they ran out of cash before they could achieve the volume needed to cover the factory costs.",tldr:"They tried to build a software margin business in a brick margin industry."},{rank:5,name:"Reali",country:"USA 🇺🇸",lootLost:"$290M",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Home Trade-In. Buy before you sell. They used their own balance sheet to buy your new home for you with cash, allowing you to move in first and sell your old house later, removing the stress of timing.",causeOfDeath:"The Interest Rate Trap. It worked when money was free. When mortgage rates spiked to 7%, the cost of holding those homes on their balance sheet exploded, and the buyer pool evaporated.",tldr:"They used Buy Now, Pay Later logic on $1,000,000 assets."},{rank:6,name:"Lyric",country:"USA 🇺🇸",lootLost:"$185M",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Marriott of Airbnb. They rented entire floors of luxury apartment buildings and converted them into Creative Suites for business travelers—consistent hotel quality with the vibe of a local rental.",causeOfDeath:"The Master Lease Suicide. They signed multi-year leases with landlords. When COVID hit and business travel went to zero, they were stuck paying rent on empty apartments that nobody could legally visit.",tldr:"They built a hotel chain that didn't own the hotels, but still owed the rent."},{rank:7,name:"Zeus Living",country:"USA 🇺🇸",lootLost:"$150M",livedYears:"~8 Years",causeTag:"UNIT ECONOMICS",valueProp:"Corporate Housing 2.0. Focused on Medium Term Stays (30+ days) for relocated tech workers. They furnished homes beautifully and managed everything, charging a premium to companies like Google.",causeOfDeath:"The Squeeze. They were caught in the middle. Landlords wanted higher rents, and tech companies started slashing relocation budgets. The margins were too thin to survive the debt they took on to acquire inventory.",tldr:"Tech companies stopped moving people, so the moving company died."},{rank:8,name:"PeerStreet",country:"USA 🇺🇸",lootLost:"$120M",livedYears:"~10 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Mortgage Marketplace. Allowed retail investors to fund short-term loans for house flippers. It was LendingClub for Real Estate, promising high yields (8-10%) backed by actual property.",causeOfDeath:"The Volume Drought. When interest rates rose, house flipping stopped. The supply of good loans dried up, and the demand from investors vanished as they could get 5% risk-free from the bank.",tldr:"Nobody wants to fund a risky house flip when a Savings Account pays 5%."},{rank:9,name:"Breather",country:"Canada 🇨🇦",lootLost:"$120M",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"Uber for Private Rooms. You could unlock a beautiful, private workspace for 1 hour or 1 day using your phone. Perfect for therapists, tutors, or meetings on the go.",causeOfDeath:"The Utilization Nightmare. To make money, they needed rooms booked almost 24/7. But people only meet during business hours. The nights and weekends vacancy killed their unit economics.",tldr:"They paid rent 24/7, but customers only visited from 9 to 5."},{rank:10,name:"Domio",country:"USA 🇺🇸",lootLost:"$115M",livedYears:"~4 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Apartment Hotel. They operated Apart-hotels in prime downtown locations, promising groups a better way to travel together than separate hotel rooms.",causeOfDeath:"Fraud & Force. An investigation revealed they were using fake host names and fake listings to bypass Airbnb's rules against commercial operators. They were banned from the platform they depended on.",tldr:"They built a business on Airbnb's back, and Airbnb broke their spine."}]},sec_clean:{title:"TOP 10: GREEN WASHED",subtitle:"Energy projects that ran out of juice.",slug:"sec_clean",icon:"♻️",items:[{rank:1,name:"Arrival",country:"UK 🇬🇧",lootLost:"$1.5B",livedYears:"~9 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Micro-factory. Attempted to reinvent auto manufacturing by ditching the traditional assembly line for Micro-factories—small, localized robot cells that could be deployed anywhere to build electric vans.",causeOfDeath:"Process Over Product. They became obsessed with reinventing how to build a car (the factory) rather than actually building the car. They burned cash on unproven robotics while Ford just kept building Transit vans.",tldr:"They tried to reinvent the assembly line before they successfully assembled a single van."},{rank:2,name:"Fisker Inc. (2.0)",country:"USA 🇺🇸",lootLost:"$1.3B",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Asset-Light EV. Henrik Fisker's second attempt, promising a stylish, affordable electric SUV (The Ocean) built by contract manufacturers (Magna) so Fisker could focus purely on design and software.",causeOfDeath:"The MKBHD Kill Shot. They shipped the car with unfinished software (key fobs didn't work, cars rolled away). A scathing review from MKBHD (The Worst Car I've Ever Reviewed) destroyed consumer trust instantly.",tldr:"They outsourced the manufacturing but forgot you can't outsource quality control."},{rank:3,name:"Solyndra",country:"USA 🇺🇸",lootLost:"$1.1B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Cylindrical Panel. They manufactured unique cylindrical solar tubes (CIGS) that could capture sunlight from any angle on white rooftops, eliminating the need for expensive mounting racks.",causeOfDeath:"The Silicon Bet. Their entire business model relied on Silicon being expensive. When Chinese manufacturing drove Silicon prices down 90%, their alternative tech became a luxury item nobody wanted.",tldr:"They bet against Silicon in a solar war, and Silicon won by a landslide."},{rank:4,name:"Fisker Auto (1.0)",country:"USA 🇺🇸",lootLost:"$1.1B",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Eco-Exotic. The Fisker Karma was the world's first true luxury plug-in hybrid—a stunningly beautiful car designed to make eco-friendly driving look sexy for celebrities (DiCaprio, Bieber).",causeOfDeath:"The Perfect Storm. A battery recall (A123 Systems) stopped production, and then Hurricane Sandy flooded their entire inventory of cars at a New Jersey port. Nature and suppliers conspired to kill them.",tldr:"Nature and bad batteries conspired to kill the most beautiful hybrid ever made."},{rank:5,name:"Proterra",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~19 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Electric Bus King. The North American leader in electric transit buses. They actually had products on the road in cities across the US, proving that heavy-duty EVs were possible.",causeOfDeath:"The Municipal Squeeze. Selling to city governments is a nightmare of low margins and complex contracts. Inflation spiked their parts cost, but their fixed-price government contracts didn't allow them to raise prices.",tldr:"Selling to the government is a great way to turn a high-tech startup into a low-margin utility."},{rank:6,name:"Better Place",country:"Israel 🇮🇱",lootLost:"$900M",livedYears:"~6 Years",causeTag:"NO MARKET NEED",valueProp:"Battery as a Service. Proposed a network of automated switching stations that could swap an EV battery in minutes, eliminating range anxiety by treating batteries like fuel tanks rather than fixed parts.",causeOfDeath:"Ecosystem Hubris. They demanded auto manufacturers redesign their car chassis to fit Better Place's batteries. Only Renault agreed. You can't build a global network if only one car fits the plug.",tldr:"They built the gas station of the future for a car that nobody bought."},{rank:7,name:"Bird",country:"USA 🇺🇸",lootLost:"$900M",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Last-Mile Freedom. The pioneer of dockless scooter sharing. They flooded cities with electric scooters to solve the last mile problem, reaching a $2.5B valuation in record time.",causeOfDeath:"The Disposable Fleet. Their early scooters were consumer-grade toys that broke in 2 months. The revenue per ride never covered the cost of constantly replacing the hardware that ended up in rivers and landfills.",tldr:"They littered the sidewalks with disposable toys and called it a transportation revolution."},{rank:8,name:"Amyris",country:"USA 🇺🇸",lootLost:"$880M",livedYears:"~20 Years",causeTag:"UNIT ECONOMICS",valueProp:"The SynBio Platform. Promised to use genetically engineered yeast to ferment sugar into anything—from renewable diesel fuel to malaria drugs and high-end skincare ingredients.",causeOfDeath:"The Scale-Up Wall. Biology is hard. Fermenting high-value molecules in a lab is easy; doing it in 50,000-liter tanks at a price competitive with oil is nearly impossible. They burned billions trying to scale the yeast.",tldr:"They spent billions teaching yeast to make oil, but the yeast demanded a higher salary than an oil rig."},{rank:9,name:"KiOR",country:"USA 🇺🇸",lootLost:"$600M",livedYears:"~7 Years",causeTag:"UNIT ECONOMICS",valueProp:"Wood into Oil. Claimed to have a proprietary catalyst that could convert standard wood chips (biomass) into drop-in crude oil in seconds, backed heavily by Vinod Khosla.",causeOfDeath:"Scientific Delusion. The yields were never real. The catalyst was expensive and degraded too fast. They were essentially cooking wood chips and pretending it was oil to keep the funding flowing.",tldr:"Alchemy for the 21st century: turning wood chips into lies."},{rank:10,name:"Abound Solar",country:"USA 🇺🇸",lootLost:"$600M",livedYears:"~5 Years",causeTag:"LEGAL",valueProp:"Cadmium Telluride. A competitor to First Solar, manufacturing thin-film panels using Cadmium Telluride (CdTe) which promised to be cheaper and better in low light than traditional Silicon.",causeOfDeath:"Defective Product. Their panels had a catastrophic failure rate (some even caught fire). When they couldn't fix the manufacturing defects, they were shut down, leaving the US taxpayers with a $400M loan guarantee loss.",tldr:"If your solar panels catch fire, you aren't saving the planet, you're just heating it up faster."}]},sec_market:{title:"TOP 10: EMPTY MARKETPLACES",subtitle:"Supply was there",slug:"sec_market",icon:"🛒",items:[{rank:1,name:"Ofo",country:"China 🇨🇳",lootLost:"$2.2B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Yellow Bike. Dockless bike sharing that allowed users to unlock a bicycle anywhere for pennies via a QR code, promising to solve the last mile commute without infrastructure.",causeOfDeath:"The Depreciation Disaster. They deployed millions of cheap bikes that broke faster than they could earn back their cost. The cost of collecting/repairing them exceeded the ride revenue.",tldr:"They tried to scale a business where the asset destroys itself."},{rank:2,name:"Fair.com",country:"USA 🇺🇸",lootLost:"$2.1B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Car Ownership is Dead. A flexible subscription model for used cars—no loans, no long-term commitment. You could drive a car for a monthly fee and return it whenever you wanted.",causeOfDeath:"The Negative Equity Machine. They bought cars (assets) that lost value faster than users paid the subscription fees. The debt on the fleet was higher than the income they generated.",tldr:"The car lost value faster than the user paid rent."},{rank:3,name:"Convoy",country:"USA 🇺🇸",lootLost:"$1B",livedYears:"~8 Years",causeTag:"NO MARKET NEED",valueProp:"Uber for Trucking. A digital freight network that used algorithms to match shippers with truckers instantly, aiming to eliminate empty miles and the manual phone-tag of traditional brokers.",causeOfDeath:"The Cyclical Trap. They built a high-fixed-cost Tech company in a boom-and-bust commodity industry. When the freight recession hit in 2023, they couldn't cut costs fast enough to survive the dip.",tldr:"They brought a Silicon Valley burn rate to a penny-pinching trucking industry."},{rank:4,name:"Zume",country:"USA 🇺🇸",lootLost:"$445M",livedYears:"~5 Years",causeTag:"RAN OUT OF CASH",valueProp:"Baked on the Way. They used robots to assemble pizzas and trucks equipped with smart ovens to cook them en route to the customer, promising the freshest slice possible.",causeOfDeath:"Engineering Overkill. Cooking on a moving truck is a nightmare (cheese slides off). It turns out, a pizza sitting in a warming bag for 10 minutes is good enough for 99% of humans.",tldr:"They spent $375M solving the problem of slightly lukewarm pizza with robots."},{rank:5,name:"Fab.com",country:"USA 🇺🇸",lootLost:"$336M",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"Design Discovery. Originally a flash-sale site for quirky, design-focused home goods and accessories that you couldn't find on Amazon, creating a sense of urgency and taste.",causeOfDeath:"The More Trap. They pivoted from unique, curated flash sales to a massive warehouse-holding retailer. They lost their cool factor and drowned in inventory that nobody wanted without the hype.",tldr:"They stopped being a curator of cool and started being a bad version of Amazon."},{rank:6,name:"Enjoy",country:"USA 🇺🇸",lootLost:"$250M",livedYears:"~8 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Store Comes to You. When you bought a new iPhone or AT&T plan, a uniformed expert delivered it to your door and spent an hour helping you set it up for free.",causeOfDeath:"Service vs. Commodity. The cost of sending a human in a van to spend an hour with a customer was higher than the margin on the phone they sold. They lost money on every single visit.",tldr:"High-touch concierge service for low-margin commodities is a charity, not a business."},{rank:7,name:"Honestbee",country:"Singapore 🇸🇬",lootLost:"$180M",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Asian Superapp. An on-demand delivery service for groceries and food across Southeast Asia, plus a futuristic Habitat retail store that combined dining and automated shopping.",causeOfDeath:"The Ego Expansion. They expanded into 8 countries simultaneously while bleeding cash. The CEO was later fired for buying a house with company money, while the futuristic store was an empty money pit.",tldr:"They tried to conquer Asia before they could even deliver groceries profitably in Singapore."},{rank:8,name:"Beepi",country:"USA 🇺🇸",lootLost:"$150M",livedYears:"~4 Years",causeTag:"RAN OUT OF CASH",valueProp:"Peer-to-Peer Cars. A used car marketplace that removed the dealership. They inspected the car, guaranteed the sale, and delivered it with a giant bow, promising a risk-free Craigslist.",causeOfDeath:"Friction & Burn. They demanded perfection (inspectors rejecting cars for tiny scratches), which choked their supply. They burned $7M/month on white glove service for a low-margin transaction.",tldr:"They treated a used Honda Civic transaction like a luxury concierge service."},{rank:9,name:"Shyp",country:"USA 🇺🇸",lootLost:"$62M",livedYears:"~5 Years",causeTag:"UNIT ECONOMICS",valueProp:"The End of the Post Office. You snapped a photo of an item, and a courier arrived to pick it up, box it, and ship it for you. It was magical for the user.",causeOfDeath:"Consumer vs. Business. Consumers ship weird shapes (lamps, vases) rarely and won't pay the true cost of packing. Businesses ship standard boxes often. Shyp pivoted to B2B too late.",tldr:"They solved a problem (packing) that customers weren't willing to pay the actual cost to solve."},{rank:10,name:"Homejoy",country:"USA 🇺🇸",lootLost:"$40M",livedYears:"~5 Years",causeTag:"UNIT ECONOMICS",valueProp:"Uber for House Cleaning. A platform connecting homeowners with freelance cleaners for a flat hourly rate ($20/hr), aiming to standardize the fragmented cleaning market.",causeOfDeath:"Platform Leakage. The moment a homeowner found a good cleaner, they exchanged numbers and paid cash to cut Homejoy out. The platform added friction (fees), not value, to the long-term relationship.",tldr:"A marketplace that introduces two people who immediately conspire to fire the marketplace."}]},sec_ai:{title:"TOP 10: ARTIFICIAL STUPIDITY",subtitle:"The first wave of AI startups that hallucinated their revenue.",slug:"sec_ai",icon:"🤖",items:[{rank:1,name:"Argo AI",country:"USA 🇺🇸",lootLost:"$3.6B",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"Level 4 for Everyone. A joint venture between Ford and VW ($3.6B raised) to build the Driverless OS for mass-market vehicles, promising to solve autonomy without the Robotaxi baggage.",causeOfDeath:"The CAPEX Cliff. They built a system that worked 99% of the time. The last 1% (edge cases) cost billions. Ford realized that Level 4 was a money pit and pivoted back to driver-assist (L2+).",tldr:"They spent $3.6B to learn that a human driver is cheaper than a robot."},{rank:2,name:"TuSimple",country:"USA/China 🇺🇸🇨🇳",lootLost:"$1B",livedYears:"~9 Years",causeTag:"CONFLICT",valueProp:"The Ghost Truck. Autonomous semi-trucks designed to haul freight on highways hub-to-hub without a human in the cab, aiming to solve the global trucker shortage.",causeOfDeath:"The Geopolitical Divorce. A Frankenstein structure (US ops + China tech) triggered an FBI probe. Combined with a terrifying safety video of a truck veering into traffic, the trust evaporated.",tldr:"You can't automate 40-ton missiles if the FBI is investigating your source code."},{rank:3,name:"Olive AI",country:"USA 🇺🇸",lootLost:"$852M",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Healthcare Bot. A Digital Worker for hospitals that promised to automate the messy backend of insurance claims and prior authorizations using AI.",causeOfDeath:"The Screen-Scraping Lie. Their AI was often just brittle screen-scraping bots (RPA) that broke whenever a website changed. They sold Intelligence but delivered Macros, and the tech debt killed them.",tldr:"They sold Artificial Intelligence but delivered Fragile Scripts."},{rank:4,name:"VisionAI",country:"USA 🇺🇸",lootLost:"$80M",livedYears:"~6 Years",causeTag:"COMPETION",valueProp:"The AI Lawyer. Built on IBM Watson, it allowed lawyers to ask natural language questions (Can I fire a pregnant employee?) and get cited case law in return.",causeOfDeath:"The Copyright Trap. They tried to scrape Westlaw's database to train their AI. Thomson Reuters sued them into oblivion. You can't disrupt the law by breaking the law.",tldr:"They fought the law (and Westlaw), and the law won."},{rank:5,name:"Isentium",country:"USA 🇺🇸",lootLost:"$50M",livedYears:"~4 Years",causeTag:"COMPETION",valueProp:"The Private Cloud. Founded by the creators of OpenStack (NASA), they sold a Cloud in a Box hardware appliance to let companies run AWS-style infrastructure on-premise.",causeOfDeath:"The Hardware Reality. They tried to sell hardware to software people. The sales cycle for a $100k server rack was too long, and AWS grew too fast. Private Cloud became a niche for the paranoid.",tldr:"They tried to sell servers to people who just wanted an API key."},{rank:6,name:"Fobo",country:"USA 🇺🇸",lootLost:"$25M",livedYears:"~6 Years",causeTag:"COMPETION",valueProp:"The Social Robot. A desktop robot that could dance, tell jokes, and recognize faces. It was supposed to be part of the family, not just a tool like Alexa.",causeOfDeath:"The Utility Gap. It cost $899 and did less than a $50 Echo Dot. It had personality but no purpose. When the servers shut down, the robots literally said goodbye to their owners and died.",tldr:"A $900 paperweight that had more personality than utility."},{rank:7,name:"Nebula",country:"USA 🇺🇸",lootLost:"$25M",livedYears:"~3 Years",causeTag:"COMPETION",valueProp:"The Behavior Predictor. An AI layer for robo-taxis that analyzed passenger behavior (vomit detection, forgotten items, aggression) to keep shared fleets clean and safe.",causeOfDeath:"The Market Timing. They built the Janitor AI for Robotaxis before the Robotaxis actually existed. They were selling windshield wipers for flying cars.",tldr:"They solved the vomit problem for a car that didn't exist yet."},{rank:8,name:"Passenger AI",country:"USA 🇺🇸",lootLost:"$15M",livedYears:"~8 Years",causeTag:"COMPETION",valueProp:"The Twitter Oracle. They mined Twitter firehose data to predict stock market moves based on consumer sentiment, selling the signals to hedge funds.",causeOfDeath:"The Signal Decay. Alpha (market edge) decays quickly. As soon as hedge funds figured out the Twitter signal, it became worthless. Plus, Twitter kept raising the price of the data.",tldr:"They sold a crystal ball that stopped working once everyone looked into it."},{rank:9,name:"Botin",country:"USA 🇺🇸",lootLost:"$15M",livedYears:"~15 Years",causeTag:"COMPETION",valueProp:"The Retail Rover. 6-foot-tall robots that roamed Walmart aisles scanning shelves for out-of-stock items, promising to fix inventory data forever.",causeOfDeath:"The Human Solution. Walmart fired them because they realized a human walking the aisle was faster, cheaper, and didn't creep out the shoppers.",tldr:"Walmart realized a teenager with an iPad was better than a $30,000 robot."},{rank:10,name:"ROSS Intelligence",country:"USA 🇺🇸",lootLost:"$13M",livedYears:"~4 Years",causeTag:"COMPETION",valueProp:"The Computer Eye. (Likely referencing a generic 'Computer Vision' failure or a specific small cap). A platform promising Universal Vision for retail analytics (heatmaps, theft detection) using standard CCTV cameras.",causeOfDeath:"The Privacy/Cost Vice. The compute cost to process 24/7 video streams was higher than the value of the data. Retailers didn't care about heatmaps enough to pay the AWS bill.",tldr:"The cost of watching the store was higher than the cost of the shoplifting."}]},sec_devtools:{title:"TOP 10: DEAD CODE",subtitle:"Dev tools that engineers refused to use.",slug:"sec_devtools",icon:"💻",items:[{rank:1,name:"Twitter Fabric",country:"USA 🇺🇸",lootLost:"$100M",livedYears:"~3 Years",causeTag:"COMPETION",valueProp:"The Mobile Engine. A massive, best-in-class suite of developer tools (Crashlytics, Digits, MoPub) that lived inside almost every top mobile app, giving Twitter a direct line to developers.",causeOfDeath:"Strategic Abandonment. Twitter couldn't figure out how to monetize developer love. They sold the entire platform to Google (Firebase) to focus on Ads, handing their biggest ecosystem leverage to a competitor.",tldr:"Twitter spent billions building the best mobile dev platform, then sold it to Google for spare parts."},{rank:2,name:"Famo.us",country:"USA 🇺🇸",lootLost:"$31M",livedYears:"~5 Years",causeTag:"COMPETION",valueProp:"60 FPS Everywhere. A JavaScript framework that promised native-level performance (60fps) in the mobile browser by bypassing the DOM and using its own 3D physics engine.",causeOfDeath:"The Standards Catch-up. They bet that browsers would stay slow. Browsers got fast. React and CSS Grid solved the layout problems natively, making Famo.us's heavy, complex custom engine obsolete.",tldr:"They built a race car engine for a browser that eventually learned to drive itself."},{rank:3,name:"Layer",country:"USA 🇺🇸",lootLost:"$22M",livedYears:"~6 Years",causeTag:"COMPETION",valueProp:"Stripe for Chat. A drop-in SDK that allowed any app to add full-featured messaging (typing indicators, read receipts) with a few lines of code.",causeOfDeath:"The Scale Trap. Chat is easy to demo but infinitely hard to scale. As customers grew, the infrastructure costs exploded, but the customers refused to pay enterprise rates for just a chat box.",tldr:"They solved the easy part of chat, but drowned in the hard part of scale."},{rank:4,name:"DotCloud",country:"USA 🇺🇸",lootLost:"$18M",livedYears:"~6 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Polyglot PaaS. A Platform-as-a-Service that let you mix and match databases and languages (Python + MongoDB + Redis) easily, competing with Heroku.",causeOfDeath:"The Pivot that Ate the Company. They built an internal tool to manage their containers called Docker. The tool became 1000x more valuable than the company. They killed DotCloud to become Docker Inc.",tldr:"The product died so the feature could conquer the world."},{rank:5,name:"Galaxy",country:"USA 🇺🇸",lootLost:"$15M",livedYears:"~9 Years",causeTag:"COMPETION",valueProp:"The Full-Stack Future. A radical JavaScript framework that blurred the line between client and server, offering Real-time by Default and a proprietary hosting platform called Galaxy.",causeOfDeath:"The Monolith Trap. It was magic until it wasn't. The ecosystem moved to modular tools (React + Webpack + Vercel). Meteor felt like a walled garden that was too hard to leave and too expensive to host.",tldr:"They tried to own the entire stack in a world that wanted to mix and match."},{rank:6,name:"WorldOs",country:"USA 🇺🇸",lootLost:"$15M",livedYears:"~5 Years",causeTag:"NO MARKET NEED",valueProp:"Linux for the Cloud. A lightweight Linux distribution and container platform (Tectonic) designed specifically for running massive clusters, pioneering the Immutable Infrastructure movement.",causeOfDeath:"The Standard War. They fought a brutal war against Docker (with rkt) and Kubernetes. Google and RedHat won the container orchestration war. RedHat bought them for $250M effectively to kill the competition.",tldr:"They invented the future of infrastructure, but RedHat owned the sales channel."},{rank:7,name:"Eloquis",country:"USA 🇺🇸",lootLost:"$15M",livedYears:"~7 Years",causeTag:"NO MARKET NEED",valueProp:"The Real-Time Database. An open-source database designed to push data to apps in real-time (no more refreshing), aiming to kill MongoDB with better developer ergonomics.",causeOfDeath:"Business vs. Tech. They built a Ferrari of a database but had no sales engine. Developers loved it for free; nobody paid for the enterprise support. They folded despite having a fanatical user base.",tldr:"The developers gave them GitHub stars, but the CTOs didn't give them contracts."},{rank:8,name:"Slauth.io",country:"Israel 🇮🇱",lootLost:"$15M",livedYears:"~2 Years",causeTag:"COMPETION",valueProp:"IAM Copilot. An AI-driven tool that auto-generated secure Identity and Access Management (IAM) policies for cloud infrastructure, promising to solve the Least Privilege headache.",causeOfDeath:"Feature vs. Product. Generating a policy is a feature, not a company. AWS and Wiz started adding these capabilities natively. The AI Wrapper couldn't defend its moat against the platforms.",tldr:"They built a feature that Amazon eventually just added to the settings menu."},{rank:9,name:"SendGrid Labs",country:"USA 🇺🇸",lootLost:"$10M",livedYears:"~6 Years",causeTag:"NO MARKET NEED",valueProp:"Backend as a Service. The original No-Code backend. You wrote mobile apps, and Parse handled the database, users, and push notifications. Acquired by Facebook for $85M.",causeOfDeath:"The Rug Pull. Facebook realized it didn't help them sell ads, so they shut it down overnight. Millions of apps broke. It taught a generation of developers never to trust a Big Tech acquired tool.",tldr:"Facebook bought the developer's best friend and took it out back to shoot it."},{rank:10,name:"PlayHaven",country:"USA 🇺🇸",lootLost:"$9M",livedYears:"~7 Years",causeTag:"COMPETION",valueProp:"The Game Engine. A suite of tools for mobile game developers to manage monetization, analytics, and player retention in one dashboard.",causeOfDeath:"The AdTech Slide. They started as a developer tool but realized the money was in ads. They pivoted so hard into being an ad network that they forgot to be a tool, and eventually got swallowed by the ad-tech consolidation.",tldr:"They started building shovels for miners and ended up just selling billboard space."}]},time_zirp:{title:"TOP 10: THE ZIRP VICTIMS",subtitle:"Companies that only lived because interest rates were 0%.",slug:"time_zirp",icon:"📉",items:[{rank:1,name:"WeWork",country:"USA 🇺🇸",lootLost:"$47B",livedYears:"~13 Years",causeTag:"UNIT ECONOMICS",valueProp:"Office as a Service. They promised to elevate the world's consciousness by subleasing trendy desks, valuing a real estate company like a SaaS company (20x revenue) because capital was infinite.",causeOfDeath:"The Duration Mismatch. They signed 15-year fixed leases (Liability) and sold 1-month memberships (Revenue). When the easy money stopped flowing to cover the burn, the rent was still due.",tldr:"They used a credit card to pay the mortgage and called it Community."},{rank:2,name:"Hopin",country:"UK/USA 🇬🇧",lootLost:"$7.7B",livedYears:"~5 Years",causeTag:"NO MARKET NEED",valueProp:"The Zoom Killer. The darling of the pandemic, raising at a $7.7B valuation to build virtual conference halls. They bought companies just to park the cash they raised.",causeOfDeath:"The Valuation Compress. A ZIRP hallucination. When rates rose, investors stopped valuing growth at all costs. They couldn't grow into their $7B valuation when the world went back to the office.",tldr:"The fastest unicorn in history became a zombie the moment the masks came off."},{rank:3,name:"SmileDirectClub",country:"USA 🇺🇸",lootLost:"$8.9B",livedYears:"~9 Years",causeTag:"LEGAL",valueProp:"Teledentistry. Sent clear aligners to your door, financing the cost for customers who couldn't afford orthodontists. They acted as the bank for their own users.",causeOfDeath:"The Credit Crunch. They had $900M in debt. When interest rates spiked, their cost of borrowing exploded, and their sub-prime customers stopped paying their monthly installments.",tldr:"They lent money to people who couldn't pay, using money they couldn't afford to borrow."},{rank:4,name:"Babylon Health",country:"UK 🇬🇧",lootLost:"$4.2B",livedYears:"~10 Years",causeTag:"UNIT ECONOMICS",valueProp:"AI Primary Care. Went public via SPAC (the ultimate ZIRP vehicle), claiming their AI could replace doctors and manage population health for cheap.",causeOfDeath:"The SPAC Hangover. They burned cash to prove growth for the SPAC. When the SPAC market froze and debt became expensive, they were left with a massive burn rate and no free money pipe to refill it.",tldr:"They built a business model that only works when the stock market is drunk."},{rank:5,name:"Olive AI",country:"USA 🇺🇸",lootLost:"$4B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Digital Worker. Valued at $4B, they promised to automate the messy billing backend of US hospitals using AI (mostly screen-scraping bots).",causeOfDeath:"The Multiple Crash. They raised money at 50x revenue because money was trash. When rates rose, VCs demanded profit. Olive was burning $10M/month to sustain a fragile product.",tldr:"They sold AI but delivered expensive consultants and fragility."},{rank:6,name:"Convoy",country:"USA 🇺🇸",lootLost:"$3.8B",livedYears:"~8 Years",causeTag:"NO MARKET NEED",valueProp:"Uber for Trucking. A digital freight network matching shippers to truckers. They used VC money to subsidize shipping costs, undercutting traditional brokers.",causeOfDeath:"The Subsidy End. Freight is a low-margin commodity. When the Freight Recession hit and capital markets tightened, they couldn't afford to subsidize every truckload anymore.",tldr:"They used Venture Capital to subsidize the price of diesel, and ran out of VC."},{rank:7,name:"Hyperloop One",country:"USA 🇺🇸",lootLost:"$3.1B",livedYears:"~10 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Vacuum Train. Promised 700mph travel in tubes. A project that requires billions in upfront CAPEX with a payoff 20 years later—only fundable when interest rates are zero.",causeOfDeath:"The Discount Rate. When you can get 5% risk-free from a bank, nobody funds a 20-year science project that might explode. The opportunity cost of capital killed the dream.",tldr:"A science project that starved to death when money started costing money."},{rank:8,name:"Fair.com",country:"USA 🇺🇸",lootLost:"$3.1B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Car Subscription. Own a car like you own Spotify. They used massive debt facilities to buy cars, then rented them out to Uber drivers and sub-prime borrowers.",causeOfDeath:"The Spread Death. They borrowed money to buy depreciating assets (cars). When rates rose, their debt payments went up, but the cars still lost value. The math broke instantly.",tldr:"They borrowed at 5% to buy assets that depreciated at 15%."},{rank:9,name:"BlockFi",country:"USA 🇺🇸",lootLost:"$3B",livedYears:"~5 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Crypto Bank. Offered 8% APY on crypto deposits when real banks offered 0.01%. They made the spread by lending to risky hedge funds (3AC/Alameda).",causeOfDeath:"The Yield Compression. When the Fed raised rates to 5%, safe money paid well. The risk premium for Crypto vanished. Why risk 100% loss for 8% yield when the Government pays 5%?",tldr:"They looked like geniuses until the Federal Reserve started paying interest."},{rank:10,name:"Katerra",country:"USA 🇺🇸",lootLost:"$3B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Tech-Enabled Construction. Softbank poured billions in to productize buildings. They tried to run a low-margin construction firm with the overhead of a high-margin tech firm.",causeOfDeath:"The Margin Call. Construction has 5% margins. Tech has 80%. You can only pretend a construction company is a tech company if Softbank pays the difference.",tldr:"Softbank paid for the factory, but the market wouldn't pay for the buildings."}]},time_covid:{title:"TOP 10: COVID BUBBLE POPS",subtitle:"Hopin clones and 15-minute delivery services.",slug:"time_covid",icon:"😷",items:[{rank:1,name:"Intelsat",country:"USA/Lux 🇺🇸🇱🇺",lootLost:"$15B",livedYears:"~56 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Satellite Incumbent. One of the world's oldest satellite operators, broadcasting TV and data for global media companies and governments.",causeOfDeath:"The Debt Restructure. Carrying $15B in legacy debt, they filed for bankruptcy in May 2020 to restructure ahead of the massive C-Band spectrum auction (5G). The pandemic accelerated the decline of their core TV broadcast revenue.",tldr:"An old giant that used bankruptcy as a strategy to pivot to 5G."},{rank:2,name:"Quibi",country:"USA 🇺🇸",lootLost:"$1.7B",livedYears:"~2 Years",causeTag:"NO MARKET NEED",valueProp:"Netflix for your Pocket. Short-form (10 min) Hollywood-quality shows designed specifically to be watched on mobile phones during subway commutes and coffee breaks.",causeOfDeath:"The Commute Killer. They launched in April 2020, the exact month the entire planet stopped commuting. Without the subway use case, nobody wanted to watch movies on a phone while sitting on their couch.",tldr:"They built a subway app for a world that started working from bed."},{rank:3,name:"OneWeb",country:"UK 🇬🇧",lootLost:"$3.3B",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"Internet from Space. A massive constellation of 648 low-earth orbit (LEO) satellites designed to beam high-speed internet to governments and airlines, competing with Starlink.",causeOfDeath:"The Capital Freeze. Building a space network requires billions in constant CAPEX. When the markets crashed in March 2020, their biggest backer (Softbank) pulled the plug on a critical funding bridge.",tldr:"They ran out of cash 74 satellites short of a working product."},{rank:4,name:"Katerra",country:"USA 🇺🇸",lootLost:"$2B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Construction in a Box. A vertically integrated construction giant that prefabricated walls and floors in factories to assemble apartment buildings like Lego sets.",causeOfDeath:"The Fixed Cost Trap. Construction is a low-margin, variable business. Katerra tried to run it with high-margin, fixed-cost factories. When COVID paused job sites, the factory overhead burned them alive.",tldr:"You can't pause a factory just because the construction site is closed."},{rank:5,name:"Boosted",country:"USA 🇺🇸",lootLost:"$80M",livedYears:"~8 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Tesla of Skateboards. High-performance electric skateboards that became the status symbol for tech workers last mile commuting in San Francisco and NYC.",causeOfDeath:"The Supply & Demand Shock. Trump's China tariffs raised their costs (Supply), and COVID lockdowns killed the commute (Demand). They were squeezed from both ends and sold for scraps to Lime.",tldr:"They built the perfect vehicle for a commute that ceased to exist."},{rank:6,name:"Stay Alfred",country:"USA 🇺🇸",lootLost:"$47M",livedYears:"~9 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Apartment Hotel. They rented entire floors of downtown apartment buildings and converted them into short-term travel rentals, offering the consistency of a hotel with the space of an Airbnb.",causeOfDeath:"The Master Lease Suicide. They signed long-term leases with landlords but relied on short-term travelers for revenue. When travel went to zero in March 2020, they had 100% occupancy costs and 0% revenue.",tldr:"They paid rent every month, but travelers stopped showing up."},{rank:7,name:"Stockwell",country:"USA 🇺🇸",lootLost:"$45M",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Pantry Box. Smart vending machines placed in office lobbies and dorms. You unlocked the door with an app, grabbed a soda or snack, and cameras charged you automatically.",causeOfDeath:"The High Touch Fear. Their entire business relied on foot traffic in offices and people touching shared surfaces. In 2020, offices emptied and nobody wanted to touch a public vending machine handle.",tldr:"A vending machine for offices that suddenly had no employees."},{rank:8,name:"Starsky Robotics",country:"USA 🇺🇸",lootLost:"$20M",livedYears:"~5 Years",causeTag:"RAN OUT OF CASH",valueProp:"Remote-Controlled Trucks. Instead of full autonomy (which is hard), they used Tele-operation—office workers driving trucks remotely for the tricky first and last mile.",causeOfDeath:"The Series B from Hell. They had a term sheet ready in Feb 2020. When the market crashed, investors got spooked by capital-intensive hardware bets and pulled out. They died due to bad timing.",tldr:"They solved the tech, but the market closed the checkbook."},{rank:9,name:"HubHaus",country:"USA 🇺🇸",lootLost:"$12M",livedYears:"~4 Years",causeTag:"NO MARKET NEED",valueProp:"Dorms for Adults. A co-living management platform that rented large houses in the Bay Area and sublet individual rooms to young professionals.",causeOfDeath:"The Roommate Flight. When the pandemic hit, young professionals fled cramped shared houses to live with parents or alone. HubHaus was left holding the leases for empty rooms.",tldr:"Nobody wants 6 roommates during a global pandemic."},{rank:10,name:"Essential",country:"USA 🇺🇸",lootLost:"$11M",livedYears:"~5 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Anti-iPhone. Founded by Andy Rubin (creator of Android), they built a titanium, modular smartphone intended to break the Apple/Samsung duopoly.",causeOfDeath:"The End of Runway. The phone flopped (bad camera), and they spent years working on a new candy bar form factor (Project Gem). They shut down in Feb 2020 just as the global supply chain began to fracture.",tldr:"A billion-dollar valuation for a phone that took worse photos than a mid-tier Samsung."}]},time_dotcom:{title:"TOP 10: DOT COM DINOSAURS",subtitle:"The original internet bubble.",slug:"time_dotcom",icon:"🦖",items:[{rank:1,name:"Excite@Home",country:"USA 🇺🇸",lootLost:"$6.7B",livedYears:"~6 Years",causeTag:"CONFLICT",valueProp:"Broadband Portal. A $6.7B merger between a search engine (Excite) and a cable provider (@Home) to monopolize high-speed internet access.",causeOfDeath:"The Culture War. The Cable Guys (suits) hated the Dotcom Guys (jeans). They spent all their time fighting over who was in charge while the product rotted and broadband became a commodity.",tldr:"A $35B marriage that ended because the parents hated each other."},{rank:2,name:"Webvan",country:"USA 🇺🇸",lootLost:"$1.2B",livedYears:"~5 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"Groceries in 30 Mins. They promised to deliver groceries to your door in a specific 30-minute window using massive, automated billion-dollar warehouses.",causeOfDeath:"The Infrastructure Trap. They built the massive infrastructure (warehouses, fleets) before they had the customers. The cost of building the perfect system bankrupted them before they could scale it.",tldr:"They spent $1B building a spaceship to deliver milk."},{rank:3,name:"Pets.com",country:"USA 🇺🇸",lootLost:"$300M",livedYears:"~2 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Sock Puppet. Online pet supplies delivered to your door. Famous for their Super Bowl ad and a sock puppet mascot that was more popular than the store.",causeOfDeath:"The Physics of Dog Food. Shipping a 50lb bag of dog food costs more than the margin on the food. They lost money on every single bag they sold but tried to make it up in volume.",tldr:"They bought a Super Bowl ad to sell dog food at a loss."},{rank:4,name:"eToys",country:"USA 🇺🇸",lootLost:"$266M",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Santa Slayer. The category killer for toys. They aimed to destroy Toys R Us by offering every toy on earth online without the chaotic store experience.",causeOfDeath:"Christmas Failure. They spent millions on ads to get orders, but their warehouses melted down during Christmas 1999. They delivered thousands of toys late (after Dec 25th), destroying their brand forever.",tldr:"They ruined Christmas for thousands of kids, and parents never forgave them."},{rank:5,name:"Kozmo.com",country:"USA 🇺🇸",lootLost:"$250M",livedYears:"~3 Years",causeTag:"UNIT ECONOMICS",valueProp:"Instant Gratification. Free, one-hour delivery of small items (movies, snacks, magazines). You could order a single pack of gum and have it delivered for free.",causeOfDeath:"Unit Economics Suicide. Paying a human to ride a bike across NYC to deliver a $2 pack of gum for free is a mathematical impossibility. They burned $280M subsidizing munchies.",tldr:"They delivered a $2 pack of gum for free and wondered why they lost money."},{rank:6,name:"Boo.com",country:"UK 🇬🇧",lootLost:"$135M",livedYears:"~2 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"Global Fashion. A high-end fashion retailer that launched simultaneously in 18 countries with a mascot (Miss Boo) and 3D product rendering.",causeOfDeath:"The Bandwidth Gap. Their site was so advanced (heavy 3D graphics) that 99% of users on dial-up modems couldn't even load the homepage. They burned $135M in 18 months on travel and champagne.",tldr:"They built a website that was too heavy for the internet to lift."},{rank:7,name:"TheGlobe.com",country:"USA 🇺🇸",lootLost:"$100M",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The First Social Network. Before Facebook/MySpace, this was the place to build a personal homepage and chat with strangers. It had the biggest IPO pop in history (+606%).",causeOfDeath:"Monetization Void. They had the traffic (users), but no idea how to turn eyeballs into money. When the stock market crashed, the eyeballs metric became worthless overnight.",tldr:"They threw the biggest party on the internet but forgot to charge a cover."},{rank:8,name:"DrKoop.com",country:"USA 🇺🇸",lootLost:"$84M",livedYears:"~4 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Celebrity Doctor. Founded by former Surgeon General C. Everett Koop, promising trusted medical advice in an era of wild internet rumors.",causeOfDeath:"Ethics for Sale. They got caught selling trusted reviews to advertisers and hospitals. When users realized the Medical Advice was just a paid ad, the trust (and traffic) evaporated.",tldr:"They turned the Surgeon General into a billboard for pharmaceutical companies."},{rank:9,name:"GovWorks",country:"USA 🇺🇸",lootLost:"$60M",livedYears:"~3 Years",causeTag:"CONFLICT",valueProp:"The Civic Portal. Promised to let citizens pay parking tickets and taxes online. Famous for being the subject of the documentary Startup.com.",causeOfDeath:"Founder Conflict. The technology worked, but the founders (best friends) spent the entire company's lifespan fighting for power. The documentary captured their friendship—and the company—imploding in real-time.",tldr:"A company that died because the founders needed couples therapy."},{rank:10,name:"Flooz.com",country:"USA 🇺🇸",lootLost:"$35M",livedYears:"~3 Years",causeTag:"LEGAL",valueProp:"Internet Money. A digital currency for online gifts, promoted by Whoopi Goldberg. You bought Flooz to give to friends, who could spend it at participating stores.",causeOfDeath:"The Russian Laundromat. It became the preferred tool for Russian organized crime to launder stolen credit cards. The FBI investigated, and the merchants fled.",tldr:"They tried to invent Bitcoin but accidentally invented a money laundering tool."}]},geo_usa:{title:"TOP 10: SV BURN PILES",subtitle:"The most expensive failures in the world.",slug:"geo_usa",icon:"🇺🇸",items:[{rank:1,name:"Silicon Valley Bank",country:"USA 🇺🇸",lootLost:"$209B",livedYears:"~40 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Founder's Wallet. The only bank that truly understood the startup lifecycle, offering venture debt, networking, and unshakeable support to founders when traditional Wall Street banks saw them as high risk.",causeOfDeath:"The Duration Mismatch. They bought safe, long-term government bonds with short-term startup deposits. When interest rates spiked, the bonds lost value, and a VC-led panic on Twitter caused a $42B bank run in 24 hours.",tldr:"They died because their customers (VCs) have a WhatsApp group and zero loyalty."},{rank:2,name:"WeWork",country:"USA 🇺🇸",lootLost:"$22B",livedYears:"~13 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Consciousness Elevator. Revolutionized office space by selling community and flexibility, offering beautifully designed, beer-on-tap workspaces for freelancers and enterprises alike without long-term leases.",causeOfDeath:"The Liability Trap. They signed 15-year lease obligations (fixed debt) but sold monthly memberships (variable revenue). When the hype died and a recession hit, the members left, but the rent was still due.",tldr:"The world's most expensive rental arbitrage disguised as a tech company."},{rank:3,name:"Pluralsight",country:"USA 🇺🇸",lootLost:"$4B",livedYears:"~20 Years",causeTag:"UNIT ECONOMICS",valueProp:"Netflix for Coders. A comprehensive technology skills platform that allowed enterprises to upskill their workforce in coding, cloud, and security through high-quality, expert-led video courses.",causeOfDeath:"The Debt Zombie. Acquired by PE (Vista) for billions in debt. When AI (ChatGPT) made coding tutorials free/commodity, their revenue couldn't cover the massive interest payments, and lenders seized the company.",tldr:"Lenders took the keys because AI made learning to code free overnight."},{rank:4,name:"Argo AI",country:"USA 🇺🇸",lootLost:"$3.6B",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"Level 4 for Everyone. Aimed to build the driver for self-driving cars—a Level 4 autonomous system funded by Ford and VW ($3.6B) to power robotaxis and delivery vehicles at massive scale.",causeOfDeath:"The Edge Case Cliff. They solved 99% of driving, but the last 1% costs billions. Ford realized a robotaxi business was a decade away and pulled the plug to focus on driver-assist (BlueCruise) instead.",tldr:"They spent $3.6B to learn that a human driver is still cheaper than a robot."},{rank:5,name:"Katerra",country:"USA 🇺🇸",lootLost:"$2.6B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Construction in a Box. Promised to fix the broken construction industry by vertically integrating everything—design, supply chain, and manufacturing—to build apartments like products on an assembly line.",causeOfDeath:"Fixed Cost Suicide. Construction is a low-margin, variable business. Katerra tried to run it with high-margin, fixed-cost factories. When COVID paused job sites, the factory overhead burned them alive.",tldr:"You can't treat a chaotic construction site like a Toyota assembly line."},{rank:6,name:"Uber Rush",country:"USA 🇺🇸",lootLost:"$2.5B",livedYears:"~4 Years",causeTag:"COMPETION",valueProp:"The API Courier. An on-demand courier API that allowed local businesses (florists, dry cleaners) to tap into Uber's fleet of drivers for same-day delivery, competing with FedEx and Postmates.",causeOfDeath:"The Cannibal. It competed with Uber's own core business. Drivers were delivering burritos instead of people, causing surge pricing for passengers. Uber killed it to focus on UberEats (higher margin).",tldr:"They accidentally DDOS'd their own taxi service with sandwiches."},{rank:7,name:"Fair.com",country:"USA 🇺🇸",lootLost:"$2.1B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Car Ownership is Dead. Tried to kill the traditional car loan with a flexible subscription app. You could get a used car on your phone with no long-term commitment and return it whenever you wanted.",causeOfDeath:"The Depreciation Math. They borrowed money to buy cars (assets) that lost value faster than users paid the subscription fees. The debt on the fleet was higher than the income they generated.",tldr:"The car lost value faster than the user paid rent."},{rank:8,name:"Quibi",country:"USA 🇺🇸",lootLost:"$1.8B",livedYears:"~2 Years",causeTag:"NO MARKET NEED",valueProp:"Netflix for your Pocket. The Netflix for your pocket—a streaming service delivering Hollywood-quality, 10-minute chapters designed specifically for viewing on mobile phones during daily commutes.",causeOfDeath:"The Commute Killer. They launched in April 2020, the exact month the entire planet stopped commuting. Without the subway use case, nobody wanted to watch movies on a phone while sitting on their couch.",tldr:"They built a subway app for a world that started working from bed."},{rank:9,name:"Solyndra",country:"USA 🇺🇸",lootLost:"$1.5B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Cylindrical Panel. Manufactured innovative cylindrical solar tubes (CIGS) designed to capture sunlight from all angles on commercial rooftops, promising easier installation and higher efficiency than flat panels.",causeOfDeath:"The Silicon Bet. Their entire business model relied on Silicon being expensive. When Chinese manufacturing drove Silicon prices down 90%, their alternative tech became a luxury item nobody wanted.",tldr:"They bet against Silicon in a solar war, and Silicon won by a landslide."},{rank:10,name:"Intarcia therapeutics",country:"USA 🇺🇸",lootLost:"$1.4B",livedYears:"~25 Years",causeTag:"LEGAL",valueProp:"The Matchstick Cure. Developed a matchstick-sized implantable pump (ITCA 650) that could continuously deliver Type 2 diabetes medication for six months, eliminating the need for daily pills or injections.",causeOfDeath:"The FDA Coverup. The FDA rejected the device for safety risks. Executives hid this rejection from investors to keep the funding rounds going ($1.7B raised). The SEC eventually charged them with fraud.",tldr:"They sold a medical miracle that the FDA had already marked as a medical hazard."}]},geo_asia:{title:"TOP 10: THE TIGER CUBS",subtitle:"High growth startups funded by aggressive global capital.",slug:"geo_asia",icon:"🐯",items:[{rank:1,name:"Ofo",country:"China 🇨🇳",lootLost:"$2.2B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Yellow Fleet. Pioneered dockless bike sharing, allowing you to scan a QR code and ride a bike for pennies anywhere in the city, aiming to solve the last mile problem without building stations.",causeOfDeath:"The Depreciation Disaster. They deployed 10M+ cheap bikes that broke in 2 months. The cost of repairing/collecting the scrap metal exceeded the pennies they earned per ride.",tldr:"They tried to scale a business where the asset destroys itself."},{rank:2,name:"Missfresh",country:"China 🇨🇳",lootLost:"$1.7B",livedYears:"~9 Years",causeTag:"UNIT ECONOMICS",valueProp:"The 30-Minute Fridge. Invented the Distributed Mini Warehouse (DMW) model—putting cold storage in every neighborhood to deliver fresh produce in under 30 minutes, faster than Alibaba.",causeOfDeath:"The Growth Fraud. To keep the stock price up, they faked revenue (transactions that never happened) and hid billions in unpaid supplier debt. When the audit hit, the cash was gone.",tldr:"They cooked the books because they couldn't cook the unit economics."},{rank:3,name:"PayTM Mall",country:"India 🇮🇳",lootLost:"$800M",livedYears:"~6 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Cashback Bazaar. An e-commerce arm of the payments giant PayTM, trying to be the Tmall of India by offering massive cashback on electronics to drive wallet usage.",causeOfDeath:"The Identity Crisis. They had no logistics (unlike Amazon) and no exclusive brands (unlike Flipkart). Users only shopped there for the 20% cashback. When the free money stopped, the users vanished.",tldr:"A store that only had customers because it was handing out free money."},{rank:4,name:"Zilingo",country:"Singapore 🇸🇬",lootLost:"$346M",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Fashion Supply Chain. A B2B platform connecting Southeast Asian merchants directly to factories, promising to digitize the chaotic Asian textile market using AI and credit scoring.",causeOfDeath:"The Theranos of Fashion. The AI was mostly manual spreadsheets, and the revenue was inflated. The CEO was suspended for financial irregularities after burning through millions on PR and vanity.",tldr:"The Tech was spreadsheets, and the Revenue was a hallucination."},{rank:5,name:"Hike",country:"India 🇮🇳",lootLost:"$261M",livedYears:"~9 Years",causeTag:"COMPETION",valueProp:"The Super App. WeChat for India. It had localized stickers, hidden chat modes for privacy (from parents), and offline messaging features to beat WhatsApp.",causeOfDeath:"The Network Wall. They had cooler features, but everyone's grandma was already on WhatsApp. You can't migrate a social graph that is cemented in culture.",tldr:"Features don't matter if your friends aren't there."},{rank:6,name:"Honestbee",country:"Singapore 🇸🇬",lootLost:"$180M",livedYears:"~5 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Concierge. Started as a premium grocery delivery service with human shoppers, then pivoted to building a futuristic, automated retail store (Habitat) to be the Eataly of Tech.",causeOfDeath:"The Ego Trip. The CEO spent millions on the Habitat vanity project while the core delivery business bled cash. They stopped paying suppliers, and the shelves went empty.",tldr:"They stopped paying the grocery bill to build a sci-fi theme park."},{rank:7,name:"GoBear",country:"Singapore 🇸🇬",lootLost:"$97M",livedYears:"~7 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Financial Tripadvisor. A metasearch engine for insurance and loans. They aggregated data to help you compare rates, promising transparency in a murky banking world.",causeOfDeath:"The Transaction Gap. They sent traffic to banks but didn't handle the transaction (booking). They got paid tiny referral fees while the banks made the real money. COVID killed the travel insurance market overnight.",tldr:"They were the window shoppers of finance, not the cashiers."},{rank:8,name:"ShopX",country:"India 🇮🇳",lootLost:"$56M",livedYears:"~7 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Retail OS. A B2B platform helping millions of local Kirana (mom-and-pop) stores go digital, offering them inventory management and access to big brands.",causeOfDeath:"The Margin Squeeze. Selling FMCG (soap/shampoo) to small shops has razor-thin margins (1-2%). They couldn't survive on those margins without a massive lending book, which they failed to build.",tldr:"They tried to digitize an industry that runs on cash and 1% margins."},{rank:9,name:"Kaodim",country:"Malaysia 🇲🇾",lootLost:"$17M",livedYears:"~8 Years",causeTag:"UNIT ECONOMICS",valueProp:"Services on Demand. The Thumbtack of SE Asia. Matched users with plumbers, cleaners, and photographers. It was the market leader for home services in the region.",causeOfDeath:"The Lockdown Crush. Their entire business depended on strangers entering your home. During 2 years of strict COVID lockdowns, their revenue went to zero, and the recovery CAC was too high.",tldr:"The government made their core product (house calls) illegal for 2 years."},{rank:10,name:"Udayy",country:"India 🇮🇳",lootLost:"$13M",livedYears:"~3 Years",causeTag:"COMPETION",valueProp:"The Live Classroom. Small-group live English and Math classes for kids (K-5), booming during the pandemic when schools were closed.",causeOfDeath:"The Reopening Shock. When schools reopened, parents canceled online classes instantly. The founders realized the online only model for 6-year-olds was a temporary COVID habit, not a permanent shift.",tldr:"They realized that Zoom for Kindergarteners was a bug, not a feature."}]},geo_eu:{title:"TOP 10: EURO-TRASHED",subtitle:"GDPR victims and localized clones that failed to scale.",slug:"geo_eu",icon:"🇪🇺",items:[{rank:1,name:"Wirecard",country:"Germany 🇩🇪",lootLost:"$21B",livedYears:"~21 Years",causeTag:"LEGAL",valueProp:"The Invisible Bank. Positioned as the PayPal of Europe and the bridge between traditional banking and the murky world of online casinos/porn, processing billions in high risk transactions.",causeOfDeath:"Accounting Fiction. It wasn't a bank; it was a hallucination. The CEO claimed €1.9B was sitting in a Philippine account. It didn't exist. They fabricated revenue to stay in the DAX 30 index.",tldr:"The Enron of Fintech: They made up the money, then sued the journalists who noticed."},{rank:2,name:"Babylon Health",country:"UK 🇬🇧",lootLost:"$4.2B",livedYears:"~10 Years",causeTag:"UNIT ECONOMICS",valueProp:"GP in Your Pocket. Promised to replace expensive human doctors with an AI chatbot that could triage symptoms, claiming it scored higher on medical exams than real practitioners.",causeOfDeath:"The Liability Gap. AI can give advice, but it can't take legal responsibility. They burned cash trying to pivot to value-based care (managing real patients) because the Chatbot business model had no payers.",tldr:"They tried to replace doctors with a chatbot, but the chatbot couldn't sign the insurance checks."},{rank:3,name:"OneWeb",country:"UK 🇬🇧",lootLost:"$3.3B",livedYears:"~8 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Euro-Starlink. A massive constellation of 648 low-earth orbit (LEO) satellites designed to secure sovereign internet access for Europe and the UK, bypassing US/Chinese control.",causeOfDeath:"The CAPEX Cliff. Building a space network is a game for governments or Elon Musk. They ran out of cash in March 2020 (COVID market freeze) just before the network was viable, wiping out early equity holders.",tldr:"They ran out of money 74 satellites short of a working product."},{rank:4,name:"Arrival",country:"UK 🇬🇧",lootLost:"$1.5B",livedYears:"~9 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Micro-Factory. They claimed they could build electric vans cheaper by ditching the assembly line for Micro-factories—small robot cells that could be deployed in local warehouses anywhere.",causeOfDeath:"Process Paralysis. They got obsessed with how to build the van (the robots) instead of building the van. The robots were harder to program than expected, and they burned $1B+ without mass production.",tldr:"They tried to reinvent the assembly line before they successfully assembled a single van."},{rank:5,name:"Cazoo",country:"UK 🇬🇧",lootLost:"$1B",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"Amazon for Cars. Click to buy, delivered to your door. They bought used cars, reconditioned them, and delivered them in branded trucks, aiming to kill the shady used car salesman.",causeOfDeath:"Unit Economics. Used cars are low margin assets. The cost of inspecting, fixing, and delivering a car to a driveway ate the entire profit margin. They sold dollars for 90 pence to show Growth.",tldr:"They brought a Silicon Valley burn rate to a low-margin used car lot."},{rank:6,name:"Sigfox",country:"France 🇫🇷",lootLost:"$300M",livedYears:"~12 Years",causeTag:"UNIT ECONOMICS",valueProp:"The 0G Network. Built a proprietary low-power network specifically for dumb IoT devices (water meters, trackers) that didn't need 5G or Wi-Fi, just tiny data bursts.",causeOfDeath:"The Standard War. They bet on a proprietary network while the telecom giants built an open standard (NB-IoT) on existing cell towers. Why build new towers when Vodafone can just flip a switch?",tldr:"They built a private dirt road next to the Superhighway."},{rank:7,name:"Britishvolt",country:"UK 🇬🇧",lootLost:"$250M",livedYears:"~3 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Powerhouse. Promised to build a massive £3.8B Gigafactory in Blyth to save the UK auto industry, securing the supply chain for Jaguar Land Rover and Lotus.",causeOfDeath:"The Real Estate Play. They had a PowerPoint and a plot of land, but no proprietary tech and no customers. They tried to fund a multi-billion dollar construction project with zero revenue or IP.",tldr:"A construction project disguised as a battery technology company."},{rank:8,name:"Powa Tech",country:"UK 🇬🇧",lootLost:"$225M",livedYears:"~9 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Magic Tag. PowaTag allowed users to scan audio or images (billboards, TV ads) to instantly buy products, valued at $2.7B at its peak.",causeOfDeath:"The Great Gatsby. The CEO threw lavish parties and rented iconic skyscrapers while the product had almost zero usage. It was a classic valuation bubble fueled by aggressive sales projections that never materialized.",tldr:"They spent more on the launch party than they made in lifetime revenue."},{rank:9,name:"VanMoof",country:"Netherlands 🇳🇱",lootLost:"$182M",livedYears:"~14 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Tesla of Bikes. Sleek, app-connected e-bikes with anti-theft tech and a cult following. They designed every single part themselves to ensure aesthetic perfection.",causeOfDeath:"The Repair Nightmare. Proprietary parts meant local bike shops couldn't fix them. When the bikes broke (often), VanMoof had to ship them back to HQ, bankrupting them on shipping and warranty costs.",tldr:"They built a bike that no bike mechanic was allowed to fix."},{rank:10,name:"Made.com",country:"UK 🇬🇧",lootLost:"$137M",livedYears:"~12 Years",causeTag:"UNIT ECONOMICS",valueProp:"Fast Furniture. Connected consumers directly to designers and factories, cutting out the middleman to sell high-end sofas for IKEA prices.",causeOfDeath:"The Supply Chain Whip. Their model relied on Just in Time shipping from Asia. When freight costs exploded from $2k to $15k per container post-COVID, their margins vanished and inventory got stuck at sea.",tldr:"The business model worked until the boat got stuck."}]},spec_speed:{title:"TOP 10: SPEED RUNS",subtitle:"How to lose $50M+ in under 24 months.",slug:"spec_speed",icon:"⚡",items:[{rank:1,name:"Quibi",country:"USA 🇺🇸",lootLost:"$1.8B",livedYears:"~6 Months",causeTag:"NO MARKET NEED",valueProp:"Hollywood in Bites. Led by heavyweights Meg Whitman and Jeffrey Katzenberg, they raised $1.75B to create TV quality 10-minute episodes designed specifically to be watched on phones during commutes.",causeOfDeath:"The Use Case Error. They launched in April 2020, when the world stopped commuting. People at home watch Netflix on a TV, not 10-minute clips on a phone. They refused to pivot or allow social sharing.",tldr:"$1.75B to build a subway companion for a world that was stuck on the couch."},{rank:2,name:"CNN+",country:"USA 🇺🇸",lootLost:"$300M",livedYears:"~1 Month",causeTag:"COMPETION",valueProp:"Premium News. A paid subscription layer for the news giant, featuring exclusive deep-dive shows from stars like Anderson Cooper and Chris Wallace, intended to capture the cord-cutting news junkie.",causeOfDeath:"Strategic Whiplash. WarnerMedia was acquired by Discovery days after the launch. The new owners (David Zaslav) saw no value in a standalone news app and killed it after just 30 days to focus on HBO Max.",tldr:"The shortest streaming service in history—murdered by a merger before the first bill went out."},{rank:3,name:"ScaleFactor",country:"USA 🇺🇸",lootLost:"$100M",livedYears:"~24 Months",causeTag:"PRODUCT/TECH FAILURE",valueProp:"Accounting on Autopilot. Promised to replace expensive accountants with AI that automatically categorized your startup's expenses and books, giving founders real-time financial clarity.",causeOfDeath:"The Mechanical Turk. The AI was actually a room full of people in the Philippines doing manual data entry. The tech didn't work, and when the error rate exploded, the customers fled.",tldr:"They sold AI Accounting that was actually just humans using QuickBooks in the dark."},{rank:4,name:"GloriFi",country:"USA 🇺🇸",lootLost:"$50M",livedYears:"~12 Months",causeTag:"CONFLICT",valueProp:"The Anti-Woke Bank. A neobank designed for conservatives who felt alienated by liberal Wall Street ESG policies. They promised credit cards made of shell casing material and mortgages for the patriotic American.",causeOfDeath:"Chaos & Incompetence. The product was vaporware. They operated out of a chaotic house in Texas, missed every launch deadline, and couldn't build a functioning banking app before the money ran out.",tldr:"They tried to fight the Culture War with a banking app, but forgot to build the bank."},{rank:5,name:"Pearl Automation",country:"USA 🇺🇸",lootLost:"$50M",livedYears:"~36 Months",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Apple of Cars. Founded by ex-Apple iPod engineers, they built a stunning, wireless backup camera frame ($500) that turned your phone into a screen, bringing modern tech to old cars.",causeOfDeath:"Niche Luxury. They over-engineered a solution for a problem (backup cameras) that was rapidly disappearing as new cars came with them standard. Who buys a $500 accessory for a 15-year-old car?",tldr:"Ex-Apple engineers built the world's most beautiful solution to a problem that cost $500 to fix."},{rank:6,name:"Airlift",country:"Pakistan 🇵🇰",lootLost:"$85M",livedYears:"~24 Months",causeTag:"NO MARKET NEED",valueProp:"Quick Commerce Frontier. Originally a bus transit app, they pivoted to 30-minute grocery delivery in Pakistan, raising $85M to build dark stores and Blitzscale in an emerging market.",causeOfDeath:"Macro Sudden Death. They relied on foreign VC cash to subsidize every order. When the global market turned in 2022, investors pulled out of frontier markets instantly. The unit economics were never positive.",tldr:"They tried to Blitzscale a Silicon Valley model in a market where the math was physically impossible."},{rank:7,name:"Fast",country:"USA 🇺🇸",lootLost:"$120M",livedYears:"~36 Months",causeTag:"RAN OUT OF CASH",valueProp:"The One-Click Button. Aimed to kill the checkout form. A ubiquitous login button that allowed you to buy anything on the internet without re-entering your credit card or address.",causeOfDeath:"Burn Rate Hubris. They burned $10M/month to generate $50k in revenue. They hired hundreds of engineers and Formula 1 sponsorships before the product actually worked on major retailer sites.",tldr:"They burned $100M selling a button that nobody clicked."},{rank:8,name:"Brandless",country:"USA 🇺🇸",lootLost:"$240M",livedYears:"~30 Months",causeTag:"UNIT ECONOMICS",valueProp:"The Anti-Brand. Sold high-quality household staples (maple syrup, knives, soap) for a flat $3 price in simple packaging, stripping away the Brand Tax of companies like P&G.",causeOfDeath:"The Softbank Curse. Softbank gave them $240M. To justify that valuation, they had to ship heavy, low-margin items (water, soup) which destroyed their shipping unit economics. The $3 price point was a trap.",tldr:"It turns out Brands exist for a reason: Trust. Selling mystery soup for $3 wasn't a business."},{rank:9,name:"IRL",country:"USA 🇺🇸",lootLost:"$200M",livedYears:"~24 Months",causeTag:"LEGAL",valueProp:"The Event Network. An app to help Gen Z discover events and meet friends In Real Life. It claimed to process billions of event impressions and have 20 million active users to reach Unicorn status.",causeOfDeath:"95% Bots. An SEC investigation revealed the 20 million users were almost entirely fake. The founder paid for user growth that was just bot farms pinging the servers.",tldr:"A social network for Real Life that was populated entirely by robots."},{rank:10,name:"Buyk",country:"USA 🇺🇸",lootLost:"$46M",livedYears:"~6 Months",causeTag:"LEGAL",valueProp:"Groceries in 15 Mins. A Russian-backed rapid delivery service in NYC/Chicago that used dark stores and bike couriers to deliver convenience items instantly, competing with Gopuff.",causeOfDeath:"Sanctioned Death. The company was funded by Sberbank (Russia). When Russia invaded Ukraine, US sanctions froze their funding sources instantly. They couldn't pay payroll and filed for bankruptcy days later.",tldr:"The only startup on this list killed by geopolitical sanctions."}]},spec_zombie:{title:"TOP 10: ZOMBIES",subtitle:"The walking dead: Long life",slug:"spec_zombie",icon:"🧟",items:[{rank:1,name:"Jawbone",country:"USA 🇺🇸",lootLost:"$900M",livedYears:"~18 Years",causeTag:"COMPETION",valueProp:"The Pivot King. Started as military headsets, pivoted to Bluetooth speakers (Jambox), then fitness trackers (UP). They chased every hardware trend but never mastered manufacturing.",causeOfDeath:"Litigation Suicide. They stopped innovating to focus on suing Fitbit for stealing trade secrets. They burned their cash on lawyers while their products bricked in customers' hands.",tldr:"They spent more time in the courtroom than the design lab."},{rank:2,name:"MediaMath",country:"USA 🇺🇸",lootLost:"$600M",livedYears:"~16 Years",causeTag:"RAN OUT OF CASH",valueProp:"AdTech OG. The first true Demand Side Platform (DSP), allowing brands to buy ads programmatically across the web. They were the Goldman Sachs of AdTech.",causeOfDeath:"The Debt Zombie. They accumulated massive debt to compete with Google. When the tech became a commodity, they couldn't service the loans. They filed for Chapter 11 with $100M+ in debt to creditors.",tldr:"An old giant that borrowed billions to fight Google and lost."},{rank:3,name:"VanMoof",country:"Netherlands 🇳🇱",lootLost:"$182M",livedYears:"~14 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Tesla of Bikes. Beautiful, app-connected e-bikes with anti-theft tech. They designed every single screw and bolt themselves to ensure aesthetic perfection.",causeOfDeath:"The Proprietary Trap. Proprietary parts meant local bike shops couldn't fix them. When the bikes broke (often), VanMoof had to ship them back to HQ, bankrupting them on shipping and warranty costs.",tldr:"They built a bike that no bike mechanic was allowed to fix."},{rank:4,name:"Mode Media",country:"USA 🇺🇸",lootLost:"$230M",livedYears:"~12 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Blog Rollup. Formerly Glam Media, they were a massive network of mommy blogs and lifestyle sites, claiming to be the #1 Lifestyle Vertical with a $1B valuation.",causeOfDeath:"The Traffic Mirage. They were an ad-network disguised as a media company. The revenue was largely projected, not real. They shut down overnight, leaving thousands of bloggers unpaid.",tldr:"A unicorn built on ad-arbitrage that vanished in 24 hours."},{rank:5,name:"ChaCha",country:"USA 🇺🇸",lootLost:"$82M",livedYears:"~10 Years",causeTag:"COMPETION",valueProp:"The Human Google. Before Siri, you texted a question to 242-242 and a human guide would Google it and text you back the answer.",causeOfDeath:"The Smart Phone. It was a bridge technology. The moment everyone got an iPhone with Safari/Google in their pocket, the need to text a human for Who won the 1998 World Series? evaporated.",tldr:"They sold Googling things for you right before everyone got Google in their pocket."},{rank:6,name:"Veoh",country:"USA 🇺🇸",lootLost:"$70M",livedYears:"~6 Years",causeTag:"LEGAL",valueProp:"The YouTube Rival. An early video hosting giant (backed by Disney) that offered higher quality and longer videos than YouTube's 10-minute limit.",causeOfDeath:"The Pyrrhic Victory. Universal Music sued them for copyright infringement. Veoh won the case (proving Safe Harbor), but the legal fees bankrupted them. They won the war but died on the battlefield.",tldr:"They beat the lawsuit, but the lawyers took all the money."},{rank:7,name:"StumbleUpon",country:"USA 🇺🇸",lootLost:"$50M",livedYears:"~16 Years",causeTag:"COMPETION",valueProp:"The Serendipity Button. A browser extension that took you to a random, cool website. It was the primary way millions of people found content before the Facebook News Feed.",causeOfDeath:"The Feed Killer. Sold to eBay, then bought back. It died because Curated Feeds (Facebook/Twitter) replaced Random Discovery. People stopped wanting random cool sites; they wanted what their friends liked.",tldr:"The internet went from Random Exploration to Algorithmic Addiction."},{rank:8,name:"Munchery",country:"USA 🇺🇸",lootLost:"$125M",livedYears:"~9 Years",causeTag:"UNIT ECONOMICS",valueProp:"Chef-Cooked Delivery. High-end meals cooked by real chefs in central kitchens, chilled, and delivered to be heated up at home.",causeOfDeath:"The Waste Scandal. They cooked massive amounts of food that never sold. Reports surfaced that they were throwing away thousands of pounds of gourmet food while bleeding cash.",tldr:"They burned VC money to cook gourmet meals for the dumpster."},{rank:9,name:"Lytro",country:"USA 🇺🇸",lootLost:"$200M",livedYears:"~12 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Focus Later. A camera that captured the Light Field, allowing you to take a photo and refocus it after you took it. Pure sci-fi magic.",causeOfDeath:"The Solution looking for a Problem. The files were huge, proprietary, and hard to share. Instagram users didn't care about refocusing; they cared about filters and likes.",tldr:"Magic technology that solved a problem nobody actually had."},{rank:10,name:"A123 Systems",country:"USA 🇺🇸",lootLost:"$370M",livedYears:"~11 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Battery Savior. Funded by massive US Govt grants to build advanced Lithium-Ion batteries for the EV revolution (Fisker, Chevy Spark).",causeOfDeath:"The Recall. A calibration error in their Michigan factory caused a massive recall for Fisker Karma batteries. The cost of replacing them destroyed their margin and reputation.",tldr:"One manufacturing defect killed the company and the car it powered."}]},spec_bootstrap:{title:"TOP 10: DAVIDS THAT DIED",subtitle:"Great ideas that just ran out of gas (Bootstrapped).",slug:"spec_bootstrap",icon:"⛺",items:[{rank:1,name:"Everpix",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~2 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Infinite Album. Used AI (before it was cool) to analyze your thousands of messy photos, hiding the blurry ones and highlighting the best ones in a clean, infinite cloud roll.",causeOfDeath:"The Cloud Bill. They spent so much time perfecting the sorting algorithm that they forgot to build a payment page. The AWS bill for hosting 55,000 users' photos arrived before the revenue did.",tldr:"They built the world's best photo gallery but forgot to ask anyone to pay for it."},{rank:2,name:"Vine",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~4 Years",causeTag:"RAN OUT OF CASH",valueProp:"The 6-Second Loop. A platform for ultra-short creativity. It spawned an entire generation of internet celebrities (Logan Paul, King Bach) by forcing users to tell a story in exactly 6 seconds.",causeOfDeath:"The Creator Revolt. Top creators asked Twitter for a salary (contracts) to keep posting. Twitter refused. The creators left for YouTube and Instagram, taking their billions of views with them.",tldr:"They built the stage, but refused to pay the actors."},{rank:3,name:"Pebble",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Original Smartwatch. The Kickstarter record-breaker ($20M raised) that put notifications on your wrist with an e-paper screen that lasted 7 days on a single charge.",causeOfDeath:"The Bezel War. They tried to scale up to fight Apple. They over-ordered inventory for the Pebble Time just as consumers decided they wanted colorful OLED screens (Apple Watch) instead of geeky e-paper.",tldr:"They tried to fight Apple with a calculator watch."},{rank:4,name:"Gowalla",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~4 Years",causeTag:"RAN OUT OF CASH",valueProp:"The Beautiful Check-in. A location game where you collected digital items and passport stamps for visiting places. It was the designer's choice alternative to Foursquare.",causeOfDeath:"Feature vs. Product. Foursquare was ugly but gamified the social status (Mayorships) better. Gowalla was pretty but useless. Facebook acqui-hired the team to build their own location features.",tldr:"They brought a sketchbook to a knife fight."},{rank:5,name:"Grooveshark",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~9 Years",causeTag:"LEGAL",valueProp:"The Free Jukebox. Allowed users to upload and stream any song for free. It was the bridge between the illegal Napster era and the legal Spotify era, beloved by broke millennials.",causeOfDeath:"Legal Suicide. It wasn't a loophole. The employees were secretly uploading copyrighted songs themselves. The labels sued them for $736M, and the founder tragically passed away shortly after.",tldr:"They tried to build a business on a foundation of 150,000 copyright lawsuits."},{rank:6,name:"Springpad",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~6 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Smart Notebook. An Evernote competitor that didn't just store notes, but understood them—if you saved a restaurant, it auto-fetched the menu and map.",causeOfDeath:"The Monetization Void. It was smarter than Evernote, but Evernote had the premium users. Springpad had 5 million users but zero revenue strategy. Google bought the team and shut it down.",tldr:"Being smarter than the competition doesn't matter if you're also poorer."},{rank:7,name:"Dinnr",country:"UK 🇬🇧",lootLost:"$0",livedYears:"~2 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Ingredient Box. Same-day delivery of pre-measured ingredients and recipes. You clicked a button, and the exact items to make Lasagna arrived at your door that evening.",causeOfDeath:"Solutionism. It turns out, if you are going to cook, you don't mind shopping. If you don't want to shop, you order a takeaway. They solved a problem (shopping) that wasn't painful enough to pay for.",tldr:"People who like cooking don't mind shopping; people who hate shopping order pizza."},{rank:8,name:"Circa News",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~4 Years",causeTag:"UNIT ECONOMICS",valueProp:"The Atomized News. They broke news stories down into atoms (facts, quotes, maps) so you could follow a story and only get notified when a new atom was added.",causeOfDeath:"Business Model Missing. They had a great UI and loyal users, but refused to put ads on the app because it would ruin the experience. They ran out of cash waiting for a subscription model that never came.",tldr:"They protected the user experience so well that they protected themselves out of business."},{rank:9,name:"Doppler Labs",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~4 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Bionic Ear. Created Here One earbuds that let you EQ the real world (turn down the crying baby, turn up the concert). It was Augmented Reality for your ears.",causeOfDeath:"Hardware is Hard. They raised $50M but the battery life was terrible (2 hours). They sold 25k units instead of the 100k needed to survive. Apple launched AirPods and crushed them.",tldr:"They raised $50M to sell earplugs that ran out of battery in 2 hours."},{rank:10,name:"Rdio",country:"USA 🇺🇸",lootLost:"$0",livedYears:"~5 Years",causeTag:"PRODUCT/TECH FAILURE",valueProp:"The Designer's Jukebox. The cleanest, most beautiful music app ever made. It pioneered the social feed for music, letting you see what your friends were listening to in real-time.",causeOfDeath:"The Freemium Miss. They refused to offer a Free Tier (Ads) because they believed music had value. Spotify gave music away for free to acquire the world. Rdio died on the moral high ground.",tldr:"They charged $10 for something their competitor was giving away for free."}]}},analysis:{"cause-of-death":{title:"THE ANATOMY OF FAILURE",denominator:"Every startup death tells the same story in different words: **a mismatch between ambition and reality**. Whether it's building for a market that doesn't exist, running out of cash before finding fit, or imploding due to internal conflict—the core pattern is ignoring early signals.",learnings:"The best founders are truth-seekers, not optimists. They pressure-test their assumptions before the market does. The graveyard is full of believers who confused vision with validation.",takeaways:[{icon:"🔮",text:"No Market: Validate the problem before you build the solution."},{icon:"🔥",text:"Cash Burn: Revenue is vanity, margin is sanity, cash is reality."},{icon:"⚔️",text:"Conflict: Hire people you trust, but trust people you can fire."}]},sectors:{title:"INDUSTRY GRAVEYARDS",denominator:"Every sector has its unique failure mode. Fintech dies from regulation and fraud. Hardware dies from manufacturing hell. SaaS dies from churn. Understanding the **sector-specific risks** is the first step to avoiding them.",learnings:"The playbook from one sector rarely transfers cleanly to another. A SaaS founder entering hardware will be humbled by atoms. A hardware founder entering SaaS will be humbled by retention.",takeaways:[{icon:"💸",text:"Fintech: Regulators move slower than you, but they hit harder."},{icon:"🧱",text:"Hardware: Atoms are harder than bits. Respect the supply chain."},{icon:"📉",text:"B2C SaaS: If you can't retain users, you're just renting them."}]},timeline:{title:"EPOCHS OF DESTRUCTION",denominator:"Market cycles create and destroy startups in waves. **ZIRP (Zero Interest Rate Policy)** created a generation of companies that could only exist when capital was free. COVID accelerated trends that then violently reversed. The Dotcom era proved that being early is the same as being wrong.",learnings:"Build for the cycle you're in, not the cycle you wish you were in. If your business model only works with cheap capital, you don't have a business—you have a trade.",takeaways:[{icon:"📉",text:"ZIRP: Cheap money hides broken unit economics."},{icon:"😷",text:"COVID: Accelerated trends can reverse just as fast."},{icon:"🦖",text:"Dotcom: Being early is indistinguishable from being wrong."}]},atlas:{title:"GEOGRAPHY OF FAILURE",denominator:"Location shapes failure modes. **Silicon Valley** dies from arrogance and overfunding. **Europe** dies from regulation and under-ambition. **Asia** dies from hyper-competition and fraud. The ecosystem you operate in dictates the risks you face.",learnings:"Understand your local advantage and your local trap. What works in San Francisco may be illegal in Berlin. What scales in Shenzhen may have no market in Singapore.",takeaways:[{icon:"🇺🇸",text:"USA: Too much capital can be as fatal as too little."},{icon:"🐯",text:"Asia: Hyper-competition means thinner margins and faster death."},{icon:"🇪🇺",text:"Europe: Regulatory compliance is a feature, not a bug."}]},special:{title:"CURATED CATASTROPHES",denominator:"These are the edge cases that don't fit neatly into boxes. **Speed Runs** prove that you can burn billions in under 24 months. **Zombies** prove that slow death is more common than fast explosions. **Bootstrapped** companies prove that even capital-efficient builders can run out of gas.",learnings:"There is no single path to failure. The startup graveyard is diverse. Learn from all of it.",takeaways:[{icon:"⚡",text:"Speed Runs: Velocity without direction is just expensive chaos."},{icon:"🧟",text:"Zombies: A long life without growth is still death."},{icon:"⛺",text:"Bootstrapped: Runway is finite even when VCs aren't involved."}]},default:{title:"THE POST-MORTEM PERSPECTIVE",denominator:"Across all sectors, the common denominator is **Scaling Ahead of Product-Market Fit**. Founders often confuse 'Interest' with 'Commitment', and start hiring and spending before the core engine is actually working.",learnings:"Entrepreneurship is a series of controlled experiments. If you treat it like a sprint to a predetermined outcome, you'll likely miss the signals that your model is broken.",takeaways:[{icon:"🧠",text:"Product-Market Fit is a quiet signal, not a loud bang."},{icon:"🔥",text:"Watch your burn like it's your own life savings (even if it isn't)."},{icon:"🎓",text:"Every failure is a curriculum. Don't waste the tuition."}]}}};export{e as T};
